   317→    /// Save captured image to Documents/LocalCaptures and return a local:// identifier
   318→    private static func saveCapturedImageToDocuments(_ image: UIImage) throws -> String {
   319→        guard let data = image.jpegData(compressionQuality: 0.92) else {
   320→            throw NSError(domain: "SouvenirApp", code: -1, userInfo: [NSLocalizedDescriptionKey: "Could not encode image as JPEG"])
   321→        }
   322→
   323→        let documentsURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
   324→        let capturesURL = documentsURL.appendingPathComponent("LocalCaptures", isDirectory: true)
   325→        try FileManager.default.createDirectory(at: capturesURL, withIntermediateDirectories: true)
   326→
   327→        let filename = "capture-\(UUID().uuidString).jpg"
   328→        let fileURL = capturesURL.appendingPathComponent(filename)
   329→        try data.write(to: fileURL, options: [.atomic])
   330→
   331→        return "local://\(filename)"
   332→    }
