   445→    private func computeResultsToShow() -> (trimmed: String, results: [ContactSearchResult]) {
   446→        let trimmed = contactQuery.trimmingCharacters(in: .whitespacesAndNewlines)
   447→        // Sort: contacts with phone numbers first, then by relevance (original order preserved within groups)
   448→        let sorted = contactResults.sorted { a, b in
   449→            let aHasPhone = resultHasPhone(a)
   450→            let bHasPhone = resultHasPhone(b)
   451→            if aHasPhone != bHasPhone { return aHasPhone }
   452→            return false  // stable: preserve relative order within each group
   453→        }
   454→        var resultsToShow = Array(sorted.prefix(7))
   455→        if resultsToShow.isEmpty, !trimmed.isEmpty {
   456→            resultsToShow = [.new(trimmed)]
   457→        }
   458→        return (trimmed, resultsToShow)
   459→    }
   460→
   461→    private func resultHasPhone(_ result: ContactSearchResult) -> Bool {
   462→        switch result {
   463→        case .local(let contact): return !(contact.phoneE164?.isEmpty ?? true)
   464→        case .system(let cn): return !cn.phoneNumbers.isEmpty
   465→        case .new: return false
   466→        }
   467→    }
   468→
   469→    private func triggerContactSearch(for query: String) {
   470→        searchTask?.cancel()
   471→        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
   472→        guard trimmed.count >= 1 else {
   473→            contactResults = []
   474→            isSearching = false
   475→            return
   476→        }
   477→
   478→        searchTask = Task {
   479→            await MainActor.run { isSearching = true }
   480→            do {
   481→                let results = try await contactService.searchAllContacts(query: trimmed, includeSystem: true)
   482→                await MainActor.run {
   483→                    contactResults = results
   484→                    isSearching = false
   485→                }
   486→            } catch {
   487→                await MainActor.run {
   488→                    contactResults = []
   489→                    isSearching = false
   490→                }
   491→            }
   492→        }
   493→    }
   494→
   495→    private func selectContactResult(_ result: ContactSearchResult) {
   496→        Task {
   497→            let contact: ContactEntity?
   498→            let displayPhone: String?
   499→            let displayEmail: String?
   500→            var displayBirthday: Date?
   501→            switch result {
   502→            case .local(let existing):
   503→                displayBirthday = existing.birthday
   504→                if existing.birthday == nil,
   505→                   ContactsSystemService().authorizationStatus() == .authorized {
   506→                    if let externalIdentifier = existing.externalIdentifier,
   507→                       let cnContact = try? await ContactsSystemService().fetchContact(identifier: externalIdentifier),
   508→                       let refreshed = try? await contactService.importSystemContact(cnContact) {
   509→                        contact = refreshed
   510→                        displayPhone = refreshed.phoneE164
   511→                        displayEmail = refreshed.email
   512→                        // Use system contact's birthday if available
   513→                        if refreshed.birthday == nil, let systemBirthdayComponents = cnContact.birthday,
   514→                           let systemBirthday = Calendar.current.date(from: systemBirthdayComponents) {
   515→                            displayBirthday = systemBirthday
   516→                        }
   517→                    } else {
   518→                        let query = existing.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
   519→                        if !query.isEmpty,
   520→                           let candidates = try? await ContactsSystemService().searchContacts(query: query) {
   521→                            let targetPhone = (existing.phoneE164 ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
   522→                            let targetEmail = (existing.email ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
   523→                            let match = candidates.first { candidate in
   524→                                if !targetEmail.isEmpty, candidate.emailAddresses.contains(where: { ($0.value as String).caseInsensitiveCompare(targetEmail) == .orderedSame }) {
   525→                                    return true
   526→                                }
   527→                                if !targetPhone.isEmpty {
   528→                                    let normalizer = ContactSearchNormalizer()
   529→                                    return candidate.phoneNumbers.contains(where: { normalizer.normalizePhone(input: $0.value.stringValue) == targetPhone })
   530→                                }
   531→                                return false
   532→                            } ?? candidates.first
   533→                            if let match,
   534→                               let refreshed = try? await contactService.importSystemContact(match) {
   535→                                contact = refreshed
   536→                                displayPhone = refreshed.phoneE164
   537→                                displayEmail = refreshed.email
   538→                                // Use system contact's birthday if available
   539→                                if refreshed.birthday == nil, let systemBirthdayComponents = match.birthday,
   540→                                   let systemBirthday = Calendar.current.date(from: systemBirthdayComponents) {
   541→                                    displayBirthday = systemBirthday
   542→                                }
   543→                            } else {
   544→                                contact = existing
   545→                                displayPhone = existing.phoneE164
   546→                                displayEmail = existing.email
   547→                            }
   548→                        } else {
   549→                            contact = existing
   550→                            displayPhone = existing.phoneE164
   551→                            displayEmail = existing.email
   552→                        }
   553→                    }
   554→                } else {
   555→                    contact = existing
   556→                    displayPhone = existing.phoneE164
   557→                    displayEmail = existing.email
   558→                }
   559→            case .system(let cnContact):
   560→                let rawPhone = cnContact.phoneNumbers.first?.value.stringValue
   561→                let rawEmail = cnContact.emailAddresses.first?.value as String?
   562→                let systemBirthdayComponents = cnContact.birthday
   563→                let systemBirthdayStr = systemBirthdayComponents.flatMap { Calendar.current.date(from: $0) }?.formatted(date: .abbreviated, time: .omitted) ?? "nil"
   564→                print("📱 System contact raw data:")
   565→                print("  rawPhone: \(rawPhone ?? "nil")")
   566→                print("  rawEmail: \(rawEmail ?? "nil")")
   567→                print("  cnContact.birthday: \(systemBirthdayStr)")
   568→                contact = try? await contactService.importSystemContact(cnContact)
   569→                displayPhone = rawPhone ?? contact?.phoneE164
   570→                displayEmail = rawEmail ?? contact?.email
   571→                displayBirthday = contact?.birthday ?? (systemBirthdayComponents.flatMap { Calendar.current.date(from: $0) })
   572→                if displayBirthday != nil {
   573→                    print("  ✅ Birthday set to: \(displayBirthday!.formatted(date: .abbreviated, time: .omitted))")
   574→                } else {
   575→                    print("  ⚠️ No birthday available from import or system contact")
   576→                }
   577→            case .new(let name):
   578→                let parts = name.split(separator: " ")
   579→                let given = parts.first.map(String.init)
   580→                let family = parts.dropFirst().joined(separator: " ")
   581→                contact = try? await contactService.createContact(givenName: given, familyName: family.isEmpty ? nil : family, phone: nil, email: nil)
   582→                displayPhone = nil
   583→                displayEmail = nil
   584→                displayBirthday = nil
   585→            }
   586→
   587→            await MainActor.run {
   588→                selectedContact = contact
   589→                nameText = contact?.displayName ?? result.displayName
   590→                phoneText = displayPhone ?? ""
   591→                emailText = displayEmail ?? ""
   592→                addressText = contact?.address ?? ""
   593→                birthday = displayBirthday
   594→                isSelfie = contact == nil ? false : (souvenir?.isSelfie ?? false)
   595→
   596→                // Log contact population for debugging
   597→                print("📋 Contact populated:")
   598→                print("  name: \(nameText)")
   599→                print("  phone: \(phoneText)")
   600→                print("  email: \(emailText)")
   601→                print("  address: \(addressText)")
   602→                print("  birthday: \(displayBirthday?.formatted(date: .abbreviated, time: .omitted) ?? "nil")")
   603→
   604→                // Dismissing ContactReviewSheet will re-show ContactSearchSheet
   605→                pendingContactSearch = true
   606→                showContactSearch = false
   607→                contactDetailsMode = .review
   608→                showContactDetails = true
   609→            }
   610→
   611→            // Persist selected contact as the souvenir's primary contact.
   612→            if let contact {
   613→                let contactID = contact.objectID
   614→                if let souvenir {
   615→                    let souvenirID = souvenir.objectID
   616→                    await viewContext.perform {
   617→                        guard let contactInContext = viewContext.object(with: contactID) as? ContactEntity,
   618→                              let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else {
   619→                            return
   620→                        }
   621→                        contactInContext.isPrimaryForSouvenir = true
   622→                        souvenirInContext.primaryContact = contactInContext
   623→                        try? viewContext.save()
   624→                    }
   625→                }
   626→            }
   627→        }
   628→    }
