   804→    private func saveContactEdits() {
   805→        guard let souvenir else { return }
   806→        guard let contact = selectedContact ?? souvenir.primaryContact else { return }
   807→        let souvenirID = souvenir.objectID
   808→        let contactID = contact.objectID
   809→        viewContext.perform {
   810→            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity,
   811→                  let contactInContext = viewContext.object(with: contactID) as? ContactEntity else { return }
   812→
   813→            contactInContext.compositeName = nameText
   814→            contactInContext.givenName = nameText
   815→            contactInContext.phoneE164 = phoneText
   816→            contactInContext.email = emailText
   817→            contactInContext.address = addressText
   818→            contactInContext.birthday = birthday
   819→
   820→            souvenirInContext.primaryContact = contactInContext
   821→            souvenirInContext.isSelfie = isSelfie
   822→            if isSelfie {
   823→                SelfContactService.shared.setSelfContactOnContextQueue(contactID: contactInContext.id, in: viewContext)
   824→            }
   825→
   826→            // Ensure permanent IDs for souvenir, contact, and any photos before presenting share
   827→            var objects: [NSManagedObject] = [souvenirInContext, contactInContext]
   828→            for p in souvenirInContext.photosArray { objects.append(p) }
   829→            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
   830→            if !tempObjects.isEmpty {
   831→                try? viewContext.obtainPermanentIDs(for: tempObjects)
   832→            }
