   851→    private func prepareForShare() {
   852→        guard let souvenir else { return }
   853→        let souvenirID = souvenir.objectID
   854→
   855→        viewContext.perform {
   856→            guard let souvenirInContext = self.viewContext.object(with: souvenirID) as? SouvenirEntity else { return }
   857→            var objects: [NSManagedObject] = [souvenirInContext]
   858→            if let contact = souvenirInContext.primaryContact { objects.append(contact) }
   859→            for p in souvenirInContext.photosArray { objects.append(p) }
   860→
   861→            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
   862→            if !tempObjects.isEmpty {
   863→                do {
   864→                    try self.viewContext.obtainPermanentIDs(for: tempObjects)
   865→                } catch {
   866→                    print("❌ Failed to obtain permanent IDs: \(error)")
   867→                    return
   868→                }
   869→            }
   870→
   871→            do {
   872→                try self.viewContext.save()
   873→            } catch {
   874→                print("❌ Failed to save before share: \(error)")
   875→                return
   876→            }
   877→
   878→            // Dismiss sheets and call callback on main thread with fresh fetch from permanent ID
   879→            DispatchQueue.main.async {
