   881→                if let persistentID = souvenirInContext.objectID as NSManagedObjectID?,
   882→                   !persistentID.isTemporaryID,
   883→                   let refreshedSouvenir = self.viewContext.object(with: persistentID) as? SouvenirEntity {
   884→                    self.onReadyToShare?(refreshedSouvenir)
   885→                }
   886→            }
   887→        }
