import SwiftUI
import CoreData
import PhotosUI
import CoreLocation
import Contacts
import UIKit

/// New add souvenir flow (replaces NewSouvenirView/CreateSouvenirView once stabilized).
struct AddSouvenirView: View {
    @Environment(\.managedObjectContext) private var viewContext
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var router: Router
    @EnvironmentObject private var newSouvenirTracker: NewSouvenirTracker

    @FetchRequest(
        sortDescriptors: [],
        predicate: NSPredicate(format: "isSelf == YES"),
        animation: .default
    )
    private var selfContacts: FetchedResults<ContactEntity>
    private typealias Tokens = DesignTokens

    var initialCapturedImage: UIImage?
    var initialCapturedLocation: CLLocation?
    var initialSelectedPhoto: PhotosPickerItem?
    var onReadyToShare: ((SouvenirEntity) -> Void)?

    @State private var souvenir: SouvenirEntity?
    @State private var backgroundImage: UIImage?
    @State private var didLoadInitialPhoto = false
    @State private var isAttachingPhoto = false
    @State private var photoReady = false

    // Contact search state
    @State private var showContactSearch = false
    @State private var showContactDetails = false
    @State private var contactDetailsMode: ContactDetailsMode = .review
    @State private var pendingContactSearch = false
    @State private var contactSearchDetent: PresentationDetent = .height(DesignTokens.ContactIsland.compactHeight)
    @State private var contactDetailsDetent: PresentationDetent = .medium

    @State private var contactQuery: String = ""
    @State private var contactResults: [ContactSearchResult] = []
    @State private var isSearching = false
    @State private var searchTask: Task<Void, Never>?
    @State private var selectedContact: ContactEntity?
    @State private var contactsPermissionStatus: CNAuthorizationStatus = .notDetermined
    @State private var showContactsPrimer = false
    @State private var shouldReopenContactSearch = false

    // Review fields
    @State private var nameText: String = ""
    @State private var phoneText: String = ""
    @State private var emailText: String = ""
    @State private var addressText: String = ""
    @State private var birthday: Date?
    @State private var isSelfie = false


    private let contactService = ContactSearchService(persistenceController: .shared)
    private enum ContactDetailsMode {
        case review
        case view
    }

    private var hasAttachedPhoto: Bool {
        if initialCapturedImage != nil || initialSelectedPhoto != nil {
            return true
        }
        if backgroundImage != nil {
            return true
        }
        if photoReady {
            return true
        }
        guard let souvenir else { return false }
        return !souvenir.photosArray.isEmpty
    }

    var body: some View {
        ZStack {
            backgroundView
                .ignoresSafeArea()
        }
        .onAppear {
            prepareDraftIfNeeded()
            let service = ContactsSystemService()
            contactsPermissionStatus = service.authorizationStatus()
            if !showContactSearch {
                showContactSearch = true
            }
        }
        .task {
            await loadInitialPhotoIfNeeded()
        }
        .sheet(isPresented: $showContactSearch, onDismiss: {}) {
            ContactSearchSheet(
                scrollDisabled: true,
                header: { contactSearchField },
                results: { contactSearchResults }
            )
            .background(ClearPresentationBackground())
            .presentationBackground(.clear)
            .presentationDragIndicator(.hidden)
            .presentationBackgroundInteraction(.enabled)
            .presentationDetents([.height(DesignTokens.ContactIsland.compactHeight), .medium], selection: $contactSearchDetent)
            .onAppear {
                contactSearchDetent = .height(DesignTokens.ContactIsland.compactHeight)
            }
        }
        .sheet(isPresented: $showContactDetails) {
            ZStack {
                if contactDetailsMode == .review {
                    ContactReviewSheet(
                        scrollDisabled: true,
                        showResults: false,
                        showDetails: true,
                        showFooter: true,
                        header: { reviewHeader },
                        results: { EmptyView() },
                        details: { reviewFields },
                        footer: { giveSouvenirButton }
                    )
                    .transition(.opacity)
                } else {
                    ContactViewSheet(
                        showDetails: true,
                        showFooter: true,
                        header: { viewHeader },
                        details: { viewDetails },
                        footer: { viewFooter }
                    )
                    .transition(.opacity)
                }
            }
            .animation(.easeInOut(duration: 0.2), value: contactDetailsMode)
            .background(ClearPresentationBackground())
            .presentationBackground(.clear)
            .presentationDragIndicator(.hidden)
            .presentationBackgroundInteraction(.enabled)
            .presentationDetents([.medium])
            .onAppear {
                contactDetailsDetent = .medium
            }
        }
        .onChange(of: showContactDetails) { _, isPresented in
            guard !isPresented else { return }
            if pendingContactSearch {
                pendingContactSearch = false
                showContactSearch = true
            }
        }
        .sheet(isPresented: $showContactsPrimer, onDismiss: {
            if shouldReopenContactSearch {
                shouldReopenContactSearch = false
                showContactSearch = true
            }
        }) {
            PermissionPrimerView(
                systemImageName: "person.crop.circle.badge.checkmark",
                title: "Search your contacts",
                message: "Allow access to find people you've already saved.",
                primaryButtonTitle: "Allow Contacts",
                secondaryButtonTitle: "Not Now",
                onContinue: {
                    let service = ContactsSystemService()
                    Task {
                        let granted = await service.requestAccess()
                        await MainActor.run {
                            contactsPermissionStatus = granted ? .authorized : .denied
                        }
                    }
                },
                onCancel: {}
            )
            .presentationBackground(.ultraThinMaterial)
            .presentationBackgroundInteraction(.enabled)
        }
    }

    @ViewBuilder
    private var backgroundView: some View {
        if let image = backgroundImage {
            Image(uiImage: image)
                .resizable()
                .aspectRatio(contentMode: .fill)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .clipped()
        } else {
            Rectangle().fill(.ultraThinMaterial)
        }
    }

    private func prepareDraftIfNeeded() {
        guard souvenir == nil else { return }
        viewContext.perform {
            let newSouvenir = SouvenirEntity(context: viewContext)
            newSouvenir.id = UUID()
            newSouvenir.createdAt = Date()
            newSouvenir.updatedAt = Date()

            let contact = ContactEntity(context: viewContext)
            contact.id = UUID()
            contact.createdAt = Date()
            contact.isPrimaryForSouvenir = true

            newSouvenir.primaryContact = contact

            DispatchQueue.main.async {
                souvenir = newSouvenir
            }
        }
    }

    @MainActor
    private func loadInitialPhotoIfNeeded() async {
        guard !didLoadInitialPhoto else { return }
        didLoadInitialPhoto = true

        if let captured = initialCapturedImage {
            backgroundImage = captured
            attachCapturedImage(captured, location: initialCapturedLocation)
            return
        }

        guard let selected = initialSelectedPhoto else { return }
        backgroundImage = await loadImage(from: selected)
        await attachSelectedPhoto(selected)
    }

    private func loadImage(from item: PhotosPickerItem) async -> UIImage? {
        guard let data = try? await item.loadTransferable(type: Data.self) else { return nil }
        return UIImage(data: data)
    }

    @MainActor
    private func attachSelectedPhoto(_ item: PhotosPickerItem) async {
        guard let souvenir else { return }
        let souvenirID = souvenir.objectID
        isAttachingPhoto = true
        let assetId: String
        if let identifier = item.itemIdentifier {
            assetId = identifier
        } else if let data = try? await item.loadTransferable(type: Data.self),
                  let image = UIImage(data: data),
                  let localId = try? Self.saveCapturedImageToDocuments(image) {
            assetId = localId
        } else {
            isAttachingPhoto = false
            return
        }
        await viewContext.perform {
            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else {
                return
            }
            let photo = PhotoEntity(context: viewContext)
            photo.id = UUID()
            photo.assetLocalId = assetId
            photo.timestamp = Date()
            photo.timezoneID = TimeZone.current.identifier
            photo.viewportScale = 1.0
            photo.viewportOffsetX = 0.0
            photo.viewportOffsetY = 0.0
            photo.isViewportLocked = true

            souvenirInContext.photos = [photo]
            souvenirInContext.favoritePhoto = photo
            souvenirInContext.invalidatePhotosCache()
            try? viewContext.save()
            DispatchQueue.main.async {
                photoReady = true
                isAttachingPhoto = false
            }
        }
    }

    private func attachCapturedImage(_ image: UIImage, location: CLLocation?) {
        guard let souvenir else { return }
        let souvenirID = souvenir.objectID
        let assetId: String
        do {
            assetId = try Self.saveCapturedImageToDocuments(image)
        } catch {
            return
        }

        isAttachingPhoto = true
        viewContext.perform {
            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else {
                return
            }
            let photo = PhotoEntity(context: viewContext)
            photo.id = UUID()
            photo.assetLocalId = assetId
            photo.timestamp = Date()
            photo.timezoneID = TimeZone.current.identifier
            photo.viewportScale = 1.0
            photo.viewportOffsetX = 0.0
            photo.viewportOffsetY = 0.0
            photo.isViewportLocked = true
            if let location {
                photo.latitude = NSNumber(value: location.coordinate.latitude)
                photo.longitude = NSNumber(value: location.coordinate.longitude)
            }

            souvenirInContext.photos = [photo]
            souvenirInContext.favoritePhoto = photo
            souvenirInContext.invalidatePhotosCache()
            try? viewContext.save()
            DispatchQueue.main.async {
                photoReady = true
                isAttachingPhoto = false
            }
        }
    }

    /// Save captured image to Documents/LocalCaptures and return a local:// identifier
    private static func saveCapturedImageToDocuments(_ image: UIImage) throws -> String {
        guard let data = image.jpegData(compressionQuality: 0.92) else {
            throw NSError(domain: "SouvenirApp", code: -1, userInfo: [NSLocalizedDescriptionKey: "Could not encode image as JPEG"])
        }

        let documentsURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
        let capturesURL = documentsURL.appendingPathComponent("LocalCaptures", isDirectory: true)
        try FileManager.default.createDirectory(at: capturesURL, withIntermediateDirectories: true)

        let filename = "capture-\(UUID().uuidString).jpg"
        let fileURL = capturesURL.appendingPathComponent(filename)
        try data.write(to: fileURL, options: [.atomic])

        return "local://\(filename)"
    }

