   393→// MARK: - Camera Controller
   394→
   395→@MainActor
   396→class CameraController: NSObject, ObservableObject {
   397→    let session = AVCaptureSession()
   398→    private let videoOutput = AVCaptureVideoDataOutput()
   399→    private var currentCamera: AVCaptureDevice?
   400→    private var frameBuffer: [UIImage] = []
   401→    private let maxBufferSize = 20  // Pre-capture frames (~0.67s at 30fps)
   402→    private var postTapFrames: [UIImage] = []
   403→    private var isCapturingPostTap = false
   404→    private var postTapTarget = 5  // Frames to capture after tap
   405→    private var burstCompletion: ((UIImage) -> Void)?
   406→    @Published var isLowLight = false
   407→    @Published var capturedImage: UIImage?
   408→    private var averageBrightness: Double = 0.5
   409→    private let analyzer = ServicesFrameQualityAnalyzer()
   410→    private let sessionID = UUID().uuidString
   411→    private var hasStopped = false  // Prevent redundant stop calls
   412→    private let videoQueue = DispatchQueue(label: "com.souvenir.videoCapture")
   413→    private let ciContext = CIContext()
   414→
   415→    @Published var flashMode: AVCaptureDevice.FlashMode = .off
   416→    @Published var cameraPosition: AVCaptureDevice.Position = .front
   417→    @Published var isAnalyzing = false
   418→
   419→    override init() {
   420→        super.init()
   421→        setupSession()
   422→        print("📹 CameraController[\(sessionID)] initialized")
   423→    }
   424→    
   425→    deinit {
   426→        print("📹 CameraController[\(sessionID)] deinitialized")
   427→        // Note: Cannot call main actor-isolated methods from deinit
   428→        // Session cleanup is handled by stopSession() which is called before dismissal
   429→    }
   430→    
   431→    private func setupSession() {
   432→        session.beginConfiguration()
   433→
   434→        // Set preset
   435→        if session.canSetSessionPreset(.photo) {
   436→            session.sessionPreset = .photo
   437→        }
   438→
   439→        // Add camera input (front camera by default)
   440→        if let camera = getCamera(for: .front) {
   441→            do {
   442→                let input = try AVCaptureDeviceInput(device: camera)
   443→                if session.canAddInput(input) {
   444→                    session.addInput(input)
   445→                    currentCamera = camera
   446→                }
   447→            } catch {
   448→                print("❌ Failed to add camera input: \(error)")
   449→            }
   450→        }
   451→
   452→        // Add video data output (silent frame capture)
   453→        videoOutput.setSampleBufferDelegate(self, queue: videoQueue)
   454→        videoOutput.alwaysDiscardsLateVideoFrames = true
   455→        if session.canAddOutput(videoOutput) {
   456→            session.addOutput(videoOutput)
   457→
   458→            // Configure output
   459→            if let connection = videoOutput.connection(with: .video) {
   460→                if connection.isVideoMirroringSupported {
   461→                    connection.isVideoMirrored = (cameraPosition == .front)
   462→                }
   463→                if connection.isVideoRotationAngleSupported(90) {
   464→                    connection.videoRotationAngle = 90
   465→                }
   466→            }
   467→        }
   468→
   469→        session.commitConfiguration()
   470→    }
   471→    
   472→    nonisolated func startSession() {
   473→        Task.detached { [weak self] in
   474→            guard let self = self else { return }
   475→            await self.session.startRunning()
   476→            await MainActor.run {
   477→                print("📹 CameraController[\(self.sessionID)] session STARTED (isRunning: \(self.session.isRunning))")
   478→                CameraStateMonitor.shared.registerSession(self.sessionID)
   479→            }
   480→        }
   481→    }
   482→    
   483→    func stopSession() {
   484→        // Guard against redundant stop calls (from capture, dismiss, disappear, deinit)
   485→        guard !hasStopped else {
   486→            return
   487→        }
   488→        hasStopped = true
   489→
   490→        // Turn off torch before stopping
   491→        setTorchMode(.off)
   492→
   493→        // Stop synchronously to ensure camera resources are released immediately
   494→        // This prevents resource contention when text input needs to initialize
   495→        print("📹 CameraController[\(sessionID)] stopSession() called (isRunning: \(session.isRunning))")
   496→
   497→        if session.isRunning {
   498→            session.stopRunning()
   499→        }
   500→
   501→        CameraStateMonitor.shared.unregisterSession(sessionID)
   502→        print("🎥 Camera session stopped for \(sessionID)")
   503→    }
   504→    
   505→    func flipCamera() {
   506→        // Turn off torch on current camera before switching
   507→        setTorchMode(.off)
   508→        flashMode = .off
   509→
   510→        let newPosition: AVCaptureDevice.Position = (cameraPosition == .front) ? .back : .front
   511→
   512→        guard let newCamera = getCamera(for: newPosition) else {
   513→            print("⚠️ Camera not available for position: \(newPosition.rawValue)")
   514→            return
   515→        }
   516→
   517→        session.beginConfiguration()
   518→
   519→        // Remove current input
   520→        if let currentInput = session.inputs.first as? AVCaptureDeviceInput {
   521→            session.removeInput(currentInput)
   522→        }
   523→
   524→        // Add new input
   525→        do {
   526→            let newInput = try AVCaptureDeviceInput(device: newCamera)
   527→            if session.canAddInput(newInput) {
   528→                session.addInput(newInput)
   529→                currentCamera = newCamera
   530→                cameraPosition = newPosition
   531→
   532→                // Update mirroring for front camera
   533→                if let connection = videoOutput.connection(with: .video),
   534→                   connection.isVideoMirroringSupported {
   535→                    connection.isVideoMirrored = (newPosition == .front)
   536→                }
   537→            }
   538→        } catch {
   539→            print("❌ Failed to flip camera: \(error)")
   540→        }
   541→
   542→        session.commitConfiguration()
   543→    }
   544→    
   545→    func toggleFlash() {
   546→        // Only allow flash on back camera (torch is only available on back)
   547→        guard cameraPosition == .back else { return }
   548→
   549→        switch flashMode {
   550→        case .off:
   551→            flashMode = .on
   552→            setTorchMode(.on)
   553→        case .on:
   554→            flashMode = .auto
   555→            setTorchMode(.off)
   556→        case .auto:
   557→            flashMode = .off
   558→            setTorchMode(.off)
   559→        @unknown default:
   560→            flashMode = .off
   561→            setTorchMode(.off)
   562→        }
   563→    }
   564→
   565→    private func setTorchMode(_ mode: AVCaptureDevice.TorchMode) {
   566→        guard let device = currentCamera, device.hasTorch else { return }
   567→        do {
   568→            try device.lockForConfiguration()
   569→            device.torchMode = mode
   570→            device.unlockForConfiguration()
   571→        } catch {
   572→            print("❌ Failed to set torch mode: \(error)")
   573→        }
   574→    }
   575→    
   576→    func captureBurst(completion: @escaping (UIImage) -> Void) {
   577→        // Grab the last 20 pre-captured frames + collect 5 new frames after tap
   578→        let preFrames = Array(frameBuffer.suffix(20))
   579→        guard !preFrames.isEmpty else {
   580→            print("⚠️ No frames in buffer yet")
   581→            completion(UIImage())
   582→            return
   583→        }
   584→
   585→        // Immediate haptic + shutter sound feedback
   586→        let impact = UIImpactFeedbackGenerator(style: .medium)
   587→        impact.impactOccurred()
   588→        playShutterSound()
   589→
   590→        postTapFrames = []
   591→        isCapturingPostTap = true
   592→        isAnalyzing = true
   593→        burstCompletion = completion
   594→        print("📸 Captured 40 pre-tap frames, collecting 5 post-tap...")
   595→    }
   596→
   597→    private func playShutterSound() {
   598→        let soundID: SystemSoundID = 1108  // iOS camera shutter sound ID
   599→        AudioServicesPlaySystemSound(soundID)
   600→    }
   601→
   602→    private nonisolated func calculateBrightness(_ image: UIImage) -> Double {
   603→        guard let cgImage = image.cgImage else { return 0.5 }
   604→        let w = min(cgImage.width, 64), h = min(cgImage.height, 64)
   605→        let bytesPerPixel = 4
   606→        var pixels = [UInt8](repeating: 0, count: w * h * bytesPerPixel)
   607→        let colorSpace = CGColorSpaceCreateDeviceRGB()
   608→        guard let ctx = CGContext(data: &pixels, width: w, height: h,
   609→                                  bitsPerComponent: 8, bytesPerRow: w * bytesPerPixel,
   610→                                  space: colorSpace,
   611→                                  bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else { return 0.5 }
   612→        ctx.draw(cgImage, in: CGRect(x: 0, y: 0, width: w, height: h))
   613→        let luminances = stride(from: 0, to: pixels.count, by: bytesPerPixel).map { i -> Double in
   614→            0.299 * Double(pixels[i]) + 0.587 * Double(pixels[i+1]) + 0.114 * Double(pixels[i+2])
   615→        }
   616→        return luminances.isEmpty ? 0.5 : luminances.reduce(0, +) / Double(luminances.count) / 255.0
   617→    }
   618→    
   619→    private func getCamera(for position: AVCaptureDevice.Position) -> AVCaptureDevice? {
   620→        // Try to get the best camera for the position
   621→        if let device = AVCaptureDevice.default(.builtInWideAngleCamera, for: .video, position: position) {
   622→            return device
   623→        }
   624→        
   625→        // Fallback to any camera in that position using AVCaptureDeviceDiscoverySession
   626→        let discoverySession = AVCaptureDevice.DiscoverySession(
   627→            deviceTypes: [.builtInWideAngleCamera, .builtInTelephotoCamera, .builtInUltraWideCamera],
   628→            mediaType: .video,
   629→            position: position
   630→        )
   631→        return discoverySession.devices.first
   632→    }
   633→}
   634→
   635→// MARK: - Video Capture Delegate
   636→
   637→extension CameraController: AVCaptureVideoDataOutputSampleBufferDelegate {
   638→    nonisolated func captureOutput(
   639→        _ output: AVCaptureOutput,
   640→        didOutput sampleBuffer: CMSampleBuffer,
   641→        from connection: AVCaptureConnection
   642→    ) {
   643→        guard let pixelBuffer = CMSampleBufferGetImageBuffer(sampleBuffer) else { return }
   644→
   645→        // Render pixel buffer to actual UIImage with pixel data
   646→        let ciImage = CIImage(cvPixelBuffer: pixelBuffer)
   647→        guard let cgImage = self.ciContext.createCGImage(ciImage, from: ciImage.extent) else { return }
   648→        let image = UIImage(cgImage: cgImage)
   649→
   650→        Task { @MainActor in
   651→            // Maintain rolling buffer of last 20 pre-capture frames
   652→            self.frameBuffer.append(image)
   653→            if self.frameBuffer.count > self.maxBufferSize {
   654→                self.frameBuffer.removeFirst()
   655→            }
   656→
   657→            // Track brightness for low-light glow
   658→            self.averageBrightness = self.calculateBrightness(image)
   659→            self.isLowLight = self.averageBrightness < 0.3
   660→
   661→            // If capturing post-tap, also collect frames after the tap
   662→            if self.isCapturingPostTap {
   663→                self.postTapFrames.append(image)
   664→                if self.postTapFrames.count >= self.postTapTarget {
   665→                    self.isCapturingPostTap = false
   666→                    // Combine 20 pre-tap + 5 post-tap frames
   667→                    let preFrames = Array(self.frameBuffer.suffix(20))
   668→                    var allFrames = preFrames
   669→                    allFrames.append(contentsOf: self.postTapFrames)
   670→                    let completion = self.burstCompletion
   671→                    self.postTapFrames = []
   672→                    self.burstCompletion = nil
   673→
   674→                    print("📸 Analyzing \(allFrames.count) frames (20 pre + 5 post)...")
   675→                    Task.detached { [weak self] in
   676→                        guard let self else { return }
   677→                        let best = await self.analyzer.bestFrame(from: allFrames)
   678→                        await MainActor.run {
   679→                            self.stopSession()  // Stop camera immediately
   680→                            self.isAnalyzing = false
   681→                            // Haptic feedback when analysis complete
   682→                            let success = UINotificationFeedbackGenerator()
   683→                            success.notificationOccurred(.success)
   684→                            print("📸 Best frame selected")
   685→                            completion?(best)
   686→                        }
   687→                    }
   688→                }
   689→            }
   690→        }
   691→    }
   692→}
