   694→// MARK: - Camera Location Manager
   695→
   696→/// Lightweight location manager to request permission when camera opens
   697→/// This ensures location is available when the photo is captured
   698→@MainActor
   699→class CameraLocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
   700→    private let manager = CLLocationManager()
   701→    
   702→    /// Current location (if available)
   703→    @Published var location: CLLocation?
   704→    private var pendingContinuations: [CheckedContinuation<CLLocation?, Never>] = []
   705→    private var timeoutTask: Task<Void, Never>?
   706→    private var isRequestingLocation = false
   707→
   708→    override init() {
   709→        super.init()
   710→        manager.delegate = self
   711→        manager.desiredAccuracy = kCLLocationAccuracyBest
   712→    }
   713→
   714→    func requestPermissionIfNeeded(promptIfNeeded: Bool = true) {
   715→        let status = manager.authorizationStatus
   716→        if status == .notDetermined {
   717→            if promptIfNeeded {
   718→                manager.requestWhenInUseAuthorization()
   719→            }
   720→        } else if status == .authorizedWhenInUse || status == .authorizedAlways {
   721→            manager.startUpdatingLocation()
   722→        }
   723→    }
   724→
   725→    /// Await a location update with a timeout (returns nil if not authorized or timed out).
   726→    func awaitCurrentLocation(timeout: TimeInterval) async -> CLLocation? {
   727→        let start = Date()
   728→        var status = manager.authorizationStatus
   729→
   730→        if status == .notDetermined {
   731→            manager.requestWhenInUseAuthorization()
   732→            while status == .notDetermined,
   733→                  Date().timeIntervalSince(start) < timeout {
   734→                try? await Task.sleep(for: .milliseconds(150))
   735→                status = manager.authorizationStatus
   736→            }
   737→        }
   738→
   739→        guard status == .authorizedWhenInUse || status == .authorizedAlways else {
   740→            return location
   741→        }
   742→        if let location = location, abs(location.timestamp.timeIntervalSinceNow) < 30 {
   743→            return location
   744→        }
   745→
   746→        let elapsed = Date().timeIntervalSince(start)
   747→        let remaining = max(0.1, timeout - elapsed)
   748→        return await withCheckedContinuation { continuation in
   749→            Task { @MainActor in
   750→                enqueueContinuation(continuation, timeout: remaining)
   751→            }
   752→        }
   753→    }
   754→
   755→    @MainActor
   756→    private func enqueueContinuation(_ continuation: CheckedContinuation<CLLocation?, Never>, timeout: TimeInterval) {
   757→        pendingContinuations.append(continuation)
   758→
   759→        guard !isRequestingLocation else { return }
   760→        isRequestingLocation = true
   761→        manager.startUpdatingLocation()
   762→
   763→        timeoutTask?.cancel()
   764→        timeoutTask = Task { @MainActor in
   765→            try? await Task.sleep(for: .seconds(timeout))
   766→            if !pendingContinuations.isEmpty {
   767→                resolvePending(with: nil)
   768→            }
   769→        }
   770→    }
   771→
   772→    @MainActor
   773→    private func resolvePending(with location: CLLocation?) {
   774→        let continuations = pendingContinuations
   775→        pendingContinuations.removeAll()
   776→        isRequestingLocation = false
   777→        timeoutTask?.cancel()
   778→        timeoutTask = nil
   779→        manager.stopUpdatingLocation()
   780→        continuations.forEach { $0.resume(returning: location) }
   781→    }
   782→
   783→    nonisolated func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
   784→        Task { @MainActor in
   785→            let status = manager.authorizationStatus
   786→            if status == .authorizedWhenInUse || status == .authorizedAlways {
   787→                manager.startUpdatingLocation()
   788→            }
   789→        }
   790→    }
   791→    
   792→    nonisolated func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
   793→        Task { @MainActor in
   794→            self.location = locations.last
   795→            resolvePending(with: locations.last)
   796→        }
   797→    }
   798→
   799→    nonisolated func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
   800→        print("❌ Location manager error: \(error.localizedDescription)")
   801→        Task { @MainActor in
   802→            resolvePending(with: nil)
   803→        }
   804→    }
   805→}
   806→
