   808→    CustomCameraView(selectedPhoto: .constant(nil)) { image, location in
   809→        print("Captured image: \(image.size)")
   810→        if let location = location {
   811→            print("Location: \(location.coordinate.latitude), \(location.coordinate.longitude)")
   812→        } else {
