// MARK: - Camera Controller

@MainActor
class CameraController: NSObject, ObservableObject {
    let session = AVCaptureSession()
    private let videoOutput = AVCaptureVideoDataOutput()
    private var currentCamera: AVCaptureDevice?
    private var frameBuffer: [UIImage] = []
    private let maxBufferSize = 20  // Pre-capture frames (~0.67s at 30fps)
    private var postTapFrames: [UIImage] = []
    private var isCapturingPostTap = false
    private var postTapTarget = 5  // Frames to capture after tap
    private var burstCompletion: ((UIImage) -> Void)?
    @Published var isLowLight = false
    @Published var capturedImage: UIImage?
    private var averageBrightness: Double = 0.5
    private let analyzer = ServicesFrameQualityAnalyzer()
    private let sessionID = UUID().uuidString
    private var hasStopped = false  // Prevent redundant stop calls
    private let videoQueue = DispatchQueue(label: "com.souvenir.videoCapture")
    private let ciContext = CIContext()

    @Published var flashMode: AVCaptureDevice.FlashMode = .off
    @Published var cameraPosition: AVCaptureDevice.Position = .front
    @Published var isAnalyzing = false

    override init() {
        super.init()
        setupSession()
        print("📹 CameraController[\(sessionID)] initialized")
    }

    deinit {
        print("📹 CameraController[\(sessionID)] deinitialized")
        // Note: Cannot call main actor-isolated methods from deinit
        // Session cleanup is handled by stopSession() which is called before dismissal
    }

    private func setupSession() {
        session.beginConfiguration()

        // Set preset
        if session.canSetSessionPreset(.photo) {
            session.sessionPreset = .photo
        }

        // Add camera input (front camera by default)
        if let camera = getCamera(for: .front) {
            do {
                let input = try AVCaptureDeviceInput(device: camera)
                if session.canAddInput(input) {
                    session.addInput(input)
                    currentCamera = camera
                }
            } catch {
                print("❌ Failed to add camera input: \(error)")
            }
        }

        // Add video data output (silent frame capture)
        videoOutput.setSampleBufferDelegate(self, queue: videoQueue)
        videoOutput.alwaysDiscardsLateVideoFrames = true
        if session.canAddOutput(videoOutput) {
            session.addOutput(videoOutput)

            // Configure output
            if let connection = videoOutput.connection(with: .video) {
                if connection.isVideoMirroringSupported {
                    connection.isVideoMirrored = (cameraPosition == .front)
                }
                if connection.isVideoRotationAngleSupported(90) {
                    connection.videoRotationAngle = 90
                }
            }
        }

        session.commitConfiguration()
    }

    nonisolated func startSession() {
        Task.detached { [weak self] in
            guard let self = self else { return }
            await self.session.startRunning()
            await MainActor.run {
                print("📹 CameraController[\(self.sessionID)] session STARTED (isRunning: \(self.session.isRunning))")
                CameraStateMonitor.shared.registerSession(self.sessionID)
            }
        }
    }

    func stopSession() {
        // Guard against redundant stop calls (from capture, dismiss, disappear, deinit)
        guard !hasStopped else {
            return
        }
        hasStopped = true

        // Turn off torch before stopping
        setTorchMode(.off)

        // Stop synchronously to ensure camera resources are released immediately
        // This prevents resource contention when text input needs to initialize
        print("📹 CameraController[\(sessionID)] stopSession() called (isRunning: \(session.isRunning))")

        if session.isRunning {
            session.stopRunning()
        }

        CameraStateMonitor.shared.unregisterSession(sessionID)
        print("🎥 Camera session stopped for \(sessionID)")
    }

    func flipCamera() {
        // Turn off torch on current camera before switching
        setTorchMode(.off)
        flashMode = .off

        let newPosition: AVCaptureDevice.Position = (cameraPosition == .front) ? .back : .front

        guard let newCamera = getCamera(for: newPosition) else {
            print("⚠️ Camera not available for position: \(newPosition.rawValue)")
            return
        }

        session.beginConfiguration()

        // Remove current input
        if let currentInput = session.inputs.first as? AVCaptureDeviceInput {
            session.removeInput(currentInput)
        }

        // Add new input
        do {
            let newInput = try AVCaptureDeviceInput(device: newCamera)
            if session.canAddInput(newInput) {
                session.addInput(newInput)
                currentCamera = newCamera
                cameraPosition = newPosition

                // Update mirroring for front camera
                if let connection = videoOutput.connection(with: .video),
                   connection.isVideoMirroringSupported {
                    connection.isVideoMirrored = (newPosition == .front)
                }
            }
        } catch {
            print("❌ Failed to flip camera: \(error)")
        }

        session.commitConfiguration()
    }

    func toggleFlash() {
        // Only allow flash on back camera (torch is only available on back)
        guard cameraPosition == .back else { return }

        switch flashMode {
        case .off:
            flashMode = .on
            setTorchMode(.on)
        case .on:
            flashMode = .auto
            setTorchMode(.off)
        case .auto:
            flashMode = .off
            setTorchMode(.off)
        @unknown default:
            flashMode = .off
            setTorchMode(.off)
        }
    }

    private func setTorchMode(_ mode: AVCaptureDevice.TorchMode) {
        guard let device = currentCamera, device.hasTorch else { return }
        do {
            try device.lockForConfiguration()
            device.torchMode = mode
            device.unlockForConfiguration()
        } catch {
            print("❌ Failed to set torch mode: \(error)")
        }
    }

    func captureBurst(completion: @escaping (UIImage) -> Void) {
        // Grab the last 20 pre-captured frames + collect 5 new frames after tap
        let preFrames = Array(frameBuffer.suffix(20))
        guard !preFrames.isEmpty else {
            print("⚠️ No frames in buffer yet")
            completion(UIImage())
            return
        }

        // Immediate haptic + shutter sound feedback
        let impact = UIImpactFeedbackGenerator(style: .medium)
        impact.impactOccurred()
        playShutterSound()

        postTapFrames = []
        isCapturingPostTap = true
        isAnalyzing = true
        burstCompletion = completion
        print("📸 Captured 40 pre-tap frames, collecting 5 post-tap...")
    }

    private func playShutterSound() {
        let soundID: SystemSoundID = 1108  // iOS camera shutter sound ID
        AudioServicesPlaySystemSound(soundID)
    }

    private nonisolated func calculateBrightness(_ image: UIImage) -> Double {
        guard let cgImage = image.cgImage else { return 0.5 }
        let w = min(cgImage.width, 64), h = min(cgImage.height, 64)
        let bytesPerPixel = 4
        var pixels = [UInt8](repeating: 0, count: w * h * bytesPerPixel)
        let colorSpace = CGColorSpaceCreateDeviceRGB()
        guard let ctx = CGContext(data: &pixels, width: w, height: h,
                                  bitsPerComponent: 8, bytesPerRow: w * bytesPerPixel,
                                  space: colorSpace,
                                  bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else { return 0.5 }
        ctx.draw(cgImage, in: CGRect(x: 0, y: 0, width: w, height: h))
        let luminances = stride(from: 0, to: pixels.count, by: bytesPerPixel).map { i -> Double in
            0.299 * Double(pixels[i]) + 0.587 * Double(pixels[i+1]) + 0.114 * Double(pixels[i+2])
        }
        return luminances.isEmpty ? 0.5 : luminances.reduce(0, +) / Double(luminances.count) / 255.0
    }

    private func getCamera(for position: AVCaptureDevice.Position) -> AVCaptureDevice? {
        // Try to get the best camera for the position
        if let device = AVCaptureDevice.default(.builtInWideAngleCamera, for: .video, position: position) {
            return device
        }

        // Fallback to any camera in that position using AVCaptureDeviceDiscoverySession
        let discoverySession = AVCaptureDevice.DiscoverySession(
            deviceTypes: [.builtInWideAngleCamera, .builtInTelephotoCamera, .builtInUltraWideCamera],
            mediaType: .video,
            position: position
        )
        return discoverySession.devices.first
    }
}

// MARK: - Video Capture Delegate

extension CameraController: AVCaptureVideoDataOutputSampleBufferDelegate {
    nonisolated func captureOutput(
        _ output: AVCaptureOutput,
        didOutput sampleBuffer: CMSampleBuffer,
        from connection: AVCaptureConnection
    ) {
        guard let pixelBuffer = CMSampleBufferGetImageBuffer(sampleBuffer) else { return }

        // Render pixel buffer to actual UIImage with pixel data
        let ciImage = CIImage(cvPixelBuffer: pixelBuffer)
        guard let cgImage = self.ciContext.createCGImage(ciImage, from: ciImage.extent) else { return }
        let image = UIImage(cgImage: cgImage)

        Task { @MainActor in
            // Maintain rolling buffer of last 20 pre-capture frames
            self.frameBuffer.append(image)
            if self.frameBuffer.count > self.maxBufferSize {
                self.frameBuffer.removeFirst()
            }

            // Track brightness for low-light glow
            self.averageBrightness = self.calculateBrightness(image)
            self.isLowLight = self.averageBrightness < 0.3

            // If capturing post-tap, also collect frames after the tap
            if self.isCapturingPostTap {
                self.postTapFrames.append(image)
                if self.postTapFrames.count >= self.postTapTarget {
                    self.isCapturingPostTap = false
                    // Combine 20 pre-tap + 5 post-tap frames
                    let preFrames = Array(self.frameBuffer.suffix(20))
                    var allFrames = preFrames
                    allFrames.append(contentsOf: self.postTapFrames)
                    let completion = self.burstCompletion
                    self.postTapFrames = []
                    self.burstCompletion = nil

                    print("📸 Analyzing \(allFrames.count) frames (20 pre + 5 post)...")
                    Task.detached { [weak self] in
                        guard let self else { return }
                        let best = await self.analyzer.bestFrame(from: allFrames)
                        await MainActor.run {
                            self.stopSession()  // Stop camera immediately
                            self.isAnalyzing = false
                            // Haptic feedback when analysis complete
                            let success = UINotificationFeedbackGenerator()
                            success.notificationOccurred(.success)
                            print("📸 Best frame selected")
                            completion?(best)
                        }
                    }
                }
            }
        }
    }
}

// MARK: - Camera Location Manager

/// Lightweight location manager to request permission when camera opens
/// This ensures location is available when the photo is captured
@MainActor
class CameraLocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
    private let manager = CLLocationManager()

    /// Current location (if available)
    @Published var location: CLLocation?
    private var pendingContinuations: [CheckedContinuation<CLLocation?, Never>] = []
    private var timeoutTask: Task<Void, Never>?
    private var isRequestingLocation = false

    override init() {
        super.init()
        manager.delegate = self
        manager.desiredAccuracy = kCLLocationAccuracyBest
    }

    func requestPermissionIfNeeded(promptIfNeeded: Bool = true) {
        let status = manager.authorizationStatus
        if status == .notDetermined {
            if promptIfNeeded {
                manager.requestWhenInUseAuthorization()
            }
        } else if status == .authorizedWhenInUse || status == .authorizedAlways {
            manager.startUpdatingLocation()
        }
    }

    /// Await a location update with a timeout (returns nil if not authorized or timed out).
    func awaitCurrentLocation(timeout: TimeInterval) async -> CLLocation? {
        let start = Date()
        var status = manager.authorizationStatus

        if status == .notDetermined {
            manager.requestWhenInUseAuthorization()
            while status == .notDetermined,
                  Date().timeIntervalSince(start) < timeout {
                try? await Task.sleep(for: .milliseconds(150))
                status = manager.authorizationStatus
            }
        }

        guard status == .authorizedWhenInUse || status == .authorizedAlways else {
            return location
        }
        if let location = location, abs(location.timestamp.timeIntervalSinceNow) < 30 {
            return location
        }

        let elapsed = Date().timeIntervalSince(start)
        let remaining = max(0.1, timeout - elapsed)
        return await withCheckedContinuation { continuation in
            Task { @MainActor in
                enqueueContinuation(continuation, timeout: remaining)
            }
        }
    }

    @MainActor
    private func enqueueContinuation(_ continuation: CheckedContinuation<CLLocation?, Never>, timeout: TimeInterval) {
        pendingContinuations.append(continuation)

        guard !isRequestingLocation else { return }
        isRequestingLocation = true
        manager.startUpdatingLocation()

        timeoutTask?.cancel()
        timeoutTask = Task { @MainActor in
            try? await Task.sleep(for: .seconds(timeout))
            if !pendingContinuations.isEmpty {
                resolvePending(with: nil)
            }
        }
    }

    @MainActor
    private func resolvePending(with location: CLLocation?) {
        let continuations = pendingContinuations
        pendingContinuations.removeAll()
        isRequestingLocation = false
        timeoutTask?.cancel()
        timeoutTask = nil
        manager.stopUpdatingLocation()
        continuations.forEach { $0.resume(returning: location) }
    }

    nonisolated func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        Task { @MainActor in
            let status = manager.authorizationStatus
            if status == .authorizedWhenInUse || status == .authorizedAlways {
                manager.startUpdatingLocation()
            }
        }
    }

    nonisolated func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        Task { @MainActor in
            self.location = locations.last
            resolvePending(with: locations.last)
        }
    }

    nonisolated func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        print("❌ Location manager error: \(error.localizedDescription)")
        Task { @MainActor in
            resolvePending(with: nil)
        }
    }
}

