import SwiftUI
import CoreData
import PhotosUI
import CoreLocation
import Contacts
import UIKit

/// New add souvenir flow (replaces NewSouvenirView/CreateSouvenirView once stabilized).
struct AddSouvenirView: View {
    @Environment(\.managedObjectContext) private var viewContext
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var router: Router
    @EnvironmentObject private var newSouvenirTracker: NewSouvenirTracker

    @FetchRequest(
        sortDescriptors: [],
        predicate: NSPredicate(format: "isSelf == YES"),
        animation: .default
    )
    private var selfContacts: FetchedResults<ContactEntity>
    private typealias Tokens = DesignTokens

    var initialCapturedImage: UIImage?
    var initialCapturedLocation: CLLocation?
    var initialSelectedPhoto: PhotosPickerItem?
    var onReadyToShare: ((SouvenirEntity) -> Void)?

    @State private var souvenir: SouvenirEntity?
    @State private var backgroundImage: UIImage?
    @State private var didLoadInitialPhoto = false
    @State private var isAttachingPhoto = false
    @State private var photoReady = false

    // Contact search state
    @State private var showContactSearch = false
    @State private var showContactDetails = false
    @State private var contactDetailsMode: ContactDetailsMode = .review
    @State private var pendingContactSearch = false
    @State private var contactSearchDetent: PresentationDetent = .height(DesignTokens.ContactIsland.compactHeight)
    @State private var contactDetailsDetent: PresentationDetent = .medium
    @State private var suppressRetakeOnDismiss = false

    @State private var contactQuery: String = ""
    @State private var contactResults: [ContactSearchResult] = []
    @State private var isSearching = false
    @State private var searchTask: Task<Void, Never>?
    @State private var selectedContact: ContactEntity?
    @State private var contactsPermissionStatus: CNAuthorizationStatus = .notDetermined
    @State private var showContactsPrimer = false
    @State private var shouldReopenContactSearch = false

    // Review fields
    @State private var nameText: String = ""
    @State private var phoneText: String = ""
    @State private var emailText: String = ""
    @State private var addressText: String = ""
    @State private var birthday: Date?
    @State private var isSelfie = false


    private let contactService = ContactSearchService(persistenceController: .shared)
    private enum ContactDetailsMode {
        case review
        case view
    }

    private var hasAttachedPhoto: Bool {
        if initialCapturedImage != nil || initialSelectedPhoto != nil {
            return true
        }
        if backgroundImage != nil {
            return true
        }
        if photoReady {
            return true
        }
        guard let souvenir else { return false }
        return !souvenir.photosArray.isEmpty
    }

    var body: some View {
        ZStack {
            backgroundView
                .ignoresSafeArea()
        }
        .onAppear {
            prepareDraftIfNeeded()
            let service = ContactsSystemService()
            contactsPermissionStatus = service.authorizationStatus()
            if !showContactSearch {
                showContactSearch = true
            }
        }
        .task {
            await loadInitialPhotoIfNeeded()
        }
        .sheet(isPresented: $showContactSearch, onDismiss: {
            guard !suppressRetakeOnDismiss else {
                suppressRetakeOnDismiss = false
                return
            }
            retake()
        }) {
            ContactSearchSheet(
                scrollDisabled: true,
                header: { contactSearchHeader },
                results: { contactSearchResults }
            )
            .background(ClearPresentationBackground())
            .presentationBackground(.clear)
            .presentationDragIndicator(.hidden)
            .presentationBackgroundInteraction(.enabled)
            .presentationDetents([.height(DesignTokens.ContactIsland.compactHeight), .medium], selection: $contactSearchDetent)
            .onAppear {
                contactSearchDetent = .height(DesignTokens.ContactIsland.compactHeight)
            }
        }
        .sheet(isPresented: $showContactDetails) {
            ZStack {
                if contactDetailsMode == .review {
                    ContactReviewSheet(
                        scrollDisabled: true,
                        showResults: false,
                        showDetails: true,
                        showFooter: true,
                        header: { reviewHeader },
                        results: { EmptyView() },
                        details: { reviewFields },
                        footer: { giveSouvenirButton }
                    )
                    .transition(.opacity)
                } else {
                    ContactViewSheet(
                        showDetails: true,
                        showFooter: true,
                        header: { viewHeader },
                        details: { viewDetails },
                        footer: { viewFooter }
                    )
                    .transition(.opacity)
                }
            }
            .animation(.easeInOut(duration: 0.2), value: contactDetailsMode)
            .background(ClearPresentationBackground())
            .presentationBackground(.clear)
            .presentationDragIndicator(.hidden)
            .presentationBackgroundInteraction(.enabled)
            .presentationDetents([.medium])
            .onAppear {
                contactDetailsDetent = .medium
            }
        }
        .onChange(of: showContactDetails) { _, isPresented in
            guard !isPresented else { return }
            if pendingContactSearch {
                pendingContactSearch = false
                showContactSearch = true
            }
        }
        .sheet(isPresented: $showContactsPrimer, onDismiss: {
            if shouldReopenContactSearch {
                shouldReopenContactSearch = false
                showContactSearch = true
            }
        }) {
            PermissionPrimerView(
                systemImageName: "person.crop.circle.badge.checkmark",
                title: "Search your contacts",
                message: "Allow access to find people you've already saved.",
                primaryButtonTitle: "Allow Contacts",
                secondaryButtonTitle: "Not Now",
                onContinue: {
                    let service = ContactsSystemService()
                    Task {
                        let granted = await service.requestAccess()
                        await MainActor.run {
                            contactsPermissionStatus = granted ? .authorized : .denied
                        }
                    }
                },
                onCancel: {}
            )
            .presentationBackground(.ultraThinMaterial)
            .presentationBackgroundInteraction(.enabled)
        }
    }

    @ViewBuilder
    private var backgroundView: some View {
        if let image = backgroundImage {
            Image(uiImage: image)
                .resizable()
                .aspectRatio(contentMode: .fill)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .clipped()
        } else {
            Rectangle().fill(.ultraThinMaterial)
        }
    }

    private func prepareDraftIfNeeded() {
        guard souvenir == nil else { return }
        viewContext.perform {
            let newSouvenir = SouvenirEntity(context: viewContext)
            newSouvenir.id = UUID()
            newSouvenir.createdAt = Date()
            newSouvenir.updatedAt = Date()

            let contact = ContactEntity(context: viewContext)
            contact.id = UUID()
            contact.createdAt = Date()
            contact.isPrimaryForSouvenir = true

            newSouvenir.primaryContact = contact

            DispatchQueue.main.async {
                souvenir = newSouvenir
            }
        }
    }

    private func retake() {
        dismiss()
    }

    @MainActor
    private func loadInitialPhotoIfNeeded() async {
        guard !didLoadInitialPhoto else { return }
        didLoadInitialPhoto = true

        if let captured = initialCapturedImage {
            backgroundImage = captured
            attachCapturedImage(captured, location: initialCapturedLocation)
            return
        }

        guard let selected = initialSelectedPhoto else { return }
        backgroundImage = await loadImage(from: selected)
        await attachSelectedPhoto(selected)
    }

    private func loadImage(from item: PhotosPickerItem) async -> UIImage? {
        guard let data = try? await item.loadTransferable(type: Data.self) else { return nil }
        return UIImage(data: data)
    }

    @MainActor
    private func attachSelectedPhoto(_ item: PhotosPickerItem) async {
        guard let souvenir else { return }
        let souvenirID = souvenir.objectID
        isAttachingPhoto = true
        let assetId: String
        if let identifier = item.itemIdentifier {
            assetId = identifier
        } else if let data = try? await item.loadTransferable(type: Data.self),
                  let image = UIImage(data: data),
                  let localId = try? Self.saveCapturedImageToDocuments(image) {
            assetId = localId
        } else {
            isAttachingPhoto = false
            return
        }
        await viewContext.perform {
            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else {
                return
            }
            let photo = PhotoEntity(context: viewContext)
            photo.id = UUID()
            photo.assetLocalId = assetId
            photo.timestamp = Date()
            photo.timezoneID = TimeZone.current.identifier
            photo.viewportScale = 1.0
            photo.viewportOffsetX = 0.0
            photo.viewportOffsetY = 0.0
            photo.isViewportLocked = true

            souvenirInContext.photos = [photo]
            souvenirInContext.favoritePhoto = photo
            souvenirInContext.invalidatePhotosCache()
            try? viewContext.save()
            DispatchQueue.main.async {
                photoReady = true
                isAttachingPhoto = false
            }
        }
    }

    private func attachCapturedImage(_ image: UIImage, location: CLLocation?) {
        guard let souvenir else { return }
        let souvenirID = souvenir.objectID
        let assetId: String
        do {
            assetId = try Self.saveCapturedImageToDocuments(image)
        } catch {
            return
        }

        isAttachingPhoto = true
        viewContext.perform {
            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else {
                return
            }
            let photo = PhotoEntity(context: viewContext)
            photo.id = UUID()
            photo.assetLocalId = assetId
            photo.timestamp = Date()
            photo.timezoneID = TimeZone.current.identifier
            photo.viewportScale = 1.0
            photo.viewportOffsetX = 0.0
            photo.viewportOffsetY = 0.0
            photo.isViewportLocked = true
            if let location {
                photo.latitude = NSNumber(value: location.coordinate.latitude)
                photo.longitude = NSNumber(value: location.coordinate.longitude)
            }

            souvenirInContext.photos = [photo]
            souvenirInContext.favoritePhoto = photo
            souvenirInContext.invalidatePhotosCache()
            try? viewContext.save()
            DispatchQueue.main.async {
                photoReady = true
                isAttachingPhoto = false
            }
        }
    }

    /// Save captured image to Documents/LocalCaptures and return a local:// identifier
    private static func saveCapturedImageToDocuments(_ image: UIImage) throws -> String {
        guard let data = image.jpegData(compressionQuality: 0.92) else {
            throw NSError(domain: "SouvenirApp", code: -1, userInfo: [NSLocalizedDescriptionKey: "Could not encode image as JPEG"])
        }

        let documentsURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
        let capturesURL = documentsURL.appendingPathComponent("LocalCaptures", isDirectory: true)
        try FileManager.default.createDirectory(at: capturesURL, withIntermediateDirectories: true)

        let filename = "capture-\(UUID().uuidString).jpg"
        let fileURL = capturesURL.appendingPathComponent(filename)
        try data.write(to: fileURL, options: [.atomic])

        return "local://\(filename)"
    }

    // MARK: - Contact Search UI

    private var contactSearchHeader: some View {
        HStack(spacing: 0) {
            Button(action: retake) {
                Image(systemName: "arrow.uturn.backward.circle")
                    .font(.title)
                    .foregroundStyle(.white)
                    .padding(12)
                    .background(.ultraThinMaterial, in: Circle())
            }
            .buttonStyle(.plain)
            .padding(.leading, DesignTokens.Spacing.small)

            GlassSearchField(
                text: $contactQuery,
                placeholder: "Who is this?",
                font: .title,
                showClear: true,
                onSubmit: {
                    triggerContactSearch(for: contactQuery)
                },
                onFocus: {
                    if contactSearchDetent != .medium {
                        contactSearchDetent = .medium
                    }
                }
            )
            .padding(DesignTokens.Spacing.small)
            .onChange(of: contactQuery) { _, newValue in
                triggerContactSearch(for: newValue)
            }
        }
    }

    @ViewBuilder
    private var contactSearchResults: some View {
        Group {
            let result = computeResultsToShow()
            let trimmed = result.trimmed
            let resultsToShow = result.results

            SearchResults(
                resultsCount: resultsToShow.count,
                hasQuery: !trimmed.isEmpty,
                isSearching: isSearching,
                showPrompt: !isContactsAuthorized,
                results: {
                    Section {
                        RoundedResultsCard {
                            ForEach(resultsToShow) { result in
                                ContactResultRow(result: result) {
                                    selectContactResult(result)
                                }
                            }
                        }
                    }
                    .listRowBackground(Color.clear)
                    .listRowInsets(EdgeInsets(top: 2, leading: Tokens.Spacing.medium, bottom: 2, trailing: Tokens.Spacing.medium))
                    .listRowSeparator(.automatic)
                },
                empty: {
                    Section {
                        Text("No matches")
                            .font(.caption)
                            .foregroundStyle(.secondary)
                    }
                    .listRowBackground(Color.clear)
                },
                loading: {
                    Section {
                        HStack {
                            Spacer()
                            ProgressView()
                            Spacer()
                        }
                    }
                    .listRowBackground(Color.clear)
                },
                prompt: {
                    Section {
                        Button {
                            if contactsPermissionStatus == .notDetermined {
                                shouldReopenContactSearch = true
                                showContactSearch = false
                                DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) {
                                    showContactsPrimer = true
                                }
                            } else {
                                openContactsSettings()
                            }
                        } label: {
                            HStack {
                                Spacer()
                                Text(contactsPermissionStatus == .notDetermined ? "Search your contacts 🧐" : "Enable Contacts ⚙️")
                                    .font(.title2.weight(.medium))
                                    .foregroundStyle(.primary)
                                Spacer()
                                if contactsPermissionStatus != .notDetermined {
                                    Image(systemName: "arrow.up.right.square")
                                        .font(.caption.weight(.semibold))
                                        .foregroundStyle(.secondary)
                                }
                            }
                            .padding(.horizontal, DesignTokens.Spacing.large)
                            .padding(.vertical, DesignTokens.Spacing.medium)
                        }
                        .buttonStyle(.plain)
                        .contentShape(Rectangle())
                        .background(.thinMaterial, in: Capsule())
                        .overlay(
                            Capsule()
                                .strokeBorder(.primary.opacity(0.2), lineWidth: 1)
                        )
                        .padding(.horizontal, DesignTokens.Spacing.medium)
                    }
                    .listRowBackground(Color.winningSvnr.opacity(DesignTokens.Opacity.healthy))
                    .listRowSeparator(.hidden)
                }
            )
        }
    }

    private func computeResultsToShow() -> (trimmed: String, results: [ContactSearchResult]) {
        let trimmed = contactQuery.trimmingCharacters(in: .whitespacesAndNewlines)
        // Sort: contacts with phone numbers first, then by relevance (original order preserved within groups)
        let sorted = contactResults.sorted { a, b in
            let aHasPhone = resultHasPhone(a)
            let bHasPhone = resultHasPhone(b)
            if aHasPhone != bHasPhone { return aHasPhone }
            return false  // stable: preserve relative order within each group
        }
        var resultsToShow = Array(sorted.prefix(7))
        if resultsToShow.isEmpty, !trimmed.isEmpty {
            resultsToShow = [.new(trimmed)]
        }
        return (trimmed, resultsToShow)
    }

    private func resultHasPhone(_ result: ContactSearchResult) -> Bool {
        switch result {
        case .local(let contact): return !(contact.phoneE164?.isEmpty ?? true)
        case .system(let cn): return !cn.phoneNumbers.isEmpty
        case .new: return false
        }
    }

    private func triggerContactSearch(for query: String) {
        searchTask?.cancel()
        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.count >= 1 else {
            contactResults = []
            isSearching = false
            return
        }

        searchTask = Task {
            await MainActor.run { isSearching = true }
            do {
                let results = try await contactService.searchAllContacts(query: trimmed, includeSystem: true)
                await MainActor.run {
                    contactResults = results
                    isSearching = false
                }
            } catch {
                await MainActor.run {
                    contactResults = []
                    isSearching = false
                }
            }
        }
    }

    private func selectContactResult(_ result: ContactSearchResult) {
        Task {
            let contact: ContactEntity?
            let displayPhone: String?
            let displayEmail: String?
            var displayBirthday: Date?
            switch result {
            case .local(let existing):
                displayBirthday = existing.birthday
                if existing.birthday == nil,
                   ContactsSystemService().authorizationStatus() == .authorized {
                    if let externalIdentifier = existing.externalIdentifier,
                       let cnContact = try? await ContactsSystemService().fetchContact(identifier: externalIdentifier),
                       let refreshed = try? await contactService.importSystemContact(cnContact) {
                        contact = refreshed
                        displayPhone = refreshed.phoneE164
                        displayEmail = refreshed.email
                        // Use system contact's birthday if available
                        if refreshed.birthday == nil, let systemBirthdayComponents = cnContact.birthday,
                           let systemBirthday = Calendar.current.date(from: systemBirthdayComponents) {
                            displayBirthday = systemBirthday
                        }
                    } else {
                        let query = existing.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
                        if !query.isEmpty,
                           let candidates = try? await ContactsSystemService().searchContacts(query: query) {
                            let targetPhone = (existing.phoneE164 ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
                            let targetEmail = (existing.email ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
                            let match = candidates.first { candidate in
                                if !targetEmail.isEmpty, candidate.emailAddresses.contains(where: { ($0.value as String).caseInsensitiveCompare(targetEmail) == .orderedSame }) {
                                    return true
                                }
                                if !targetPhone.isEmpty {
                                    let normalizer = ContactSearchNormalizer()
                                    return candidate.phoneNumbers.contains(where: { normalizer.normalizePhone(input: $0.value.stringValue) == targetPhone })
                                }
                                return false
                            } ?? candidates.first
                            if let match,
                               let refreshed = try? await contactService.importSystemContact(match) {
                                contact = refreshed
                                displayPhone = refreshed.phoneE164
                                displayEmail = refreshed.email
                                // Use system contact's birthday if available
                                if refreshed.birthday == nil, let systemBirthdayComponents = match.birthday,
                                   let systemBirthday = Calendar.current.date(from: systemBirthdayComponents) {
                                    displayBirthday = systemBirthday
                                }
                            } else {
                                contact = existing
                                displayPhone = existing.phoneE164
                                displayEmail = existing.email
                            }
                        } else {
                            contact = existing
                            displayPhone = existing.phoneE164
                            displayEmail = existing.email
                        }
                    }
                } else {
                    contact = existing
                    displayPhone = existing.phoneE164
                    displayEmail = existing.email
                }
            case .system(let cnContact):
                let rawPhone = cnContact.phoneNumbers.first?.value.stringValue
                let rawEmail = cnContact.emailAddresses.first?.value as String?
                let systemBirthdayComponents = cnContact.birthday
                let systemBirthdayStr = systemBirthdayComponents.flatMap { Calendar.current.date(from: $0) }?.formatted(date: .abbreviated, time: .omitted) ?? "nil"
                print("📱 System contact raw data:")
                print("  rawPhone: \(rawPhone ?? "nil")")
                print("  rawEmail: \(rawEmail ?? "nil")")
                print("  cnContact.birthday: \(systemBirthdayStr)")
                contact = try? await contactService.importSystemContact(cnContact)
                displayPhone = rawPhone ?? contact?.phoneE164
                displayEmail = rawEmail ?? contact?.email
                displayBirthday = contact?.birthday ?? (systemBirthdayComponents.flatMap { Calendar.current.date(from: $0) })
                if displayBirthday != nil {
                    print("  ✅ Birthday set to: \(displayBirthday!.formatted(date: .abbreviated, time: .omitted))")
                } else {
                    print("  ⚠️ No birthday available from import or system contact")
                }
            case .new(let name):
                let parts = name.split(separator: " ")
                let given = parts.first.map(String.init)
                let family = parts.dropFirst().joined(separator: " ")
                contact = try? await contactService.createContact(givenName: given, familyName: family.isEmpty ? nil : family, phone: nil, email: nil)
                displayPhone = nil
                displayEmail = nil
                displayBirthday = nil
            }

            await MainActor.run {
                selectedContact = contact
                nameText = contact?.displayName ?? result.displayName
                phoneText = displayPhone ?? ""
                emailText = displayEmail ?? ""
                addressText = contact?.address ?? ""
                birthday = displayBirthday
                isSelfie = contact == nil ? false : (souvenir?.isSelfie ?? false)

                // Log contact population for debugging
                print("📋 Contact populated:")
                print("  name: \(nameText)")
                print("  phone: \(phoneText)")
                print("  email: \(emailText)")
                print("  address: \(addressText)")
                print("  birthday: \(displayBirthday?.formatted(date: .abbreviated, time: .omitted) ?? "nil")")

                // Dismissing ContactReviewSheet will re-show ContactSearchSheet
                suppressRetakeOnDismiss = true
                showContactSearch = false
                pendingContactSearch = true
                contactDetailsMode = .review
                showContactDetails = true
            }

            // Persist selected contact as the souvenir's primary contact.
            if let contact {
                let contactID = contact.objectID
                if let souvenir {
                    let souvenirID = souvenir.objectID
                    await viewContext.perform {
                        guard let contactInContext = viewContext.object(with: contactID) as? ContactEntity,
                              let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else {
                            return
                        }
                        contactInContext.isPrimaryForSouvenir = true
                        souvenirInContext.primaryContact = contactInContext
                        try? viewContext.save()
                    }
                }
            }
        }
    }

    private var isContactsAuthorized: Bool {
        contactsPermissionStatus == .authorized
    }

    private func openContactsSettings() {
        guard let url = URL(string: UIApplication.openSettingsURLString) else { return }
        UIApplication.shared.open(url)
    }

    // MARK: - Review / View

    private var reviewHeader: some View {
        EmptyView()
    }

    private var reviewFields: some View {
            ContactReviewDetailsView(
                avatarData: reviewContactImageData,
                displayName: $nameText,
                headerEmail: shouldShowEmailField ? emailText : nil,
                isSelfie: $isSelfie,
            onToggleSelfie: {
                if let souvenir {
                    let souvenirID = souvenir.objectID
                    let updated = isSelfie
                    viewContext.perform {
                        guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else { return }
                        souvenirInContext.isSelfie = updated
                        try? viewContext.save()
                    }
                }
            },
            showsSelfieToggle: selfContacts.isEmpty,
                phone: $phoneText,
                email: $emailText,
                address: $addressText,
                birthday: birthdayBinding,
                showsEmailField: shouldShowEmailField,
                showsAddressField: shouldShowAddressField,
                showsBirthtimeField: false,
                extra: { EmptyView() }
            )
    }

    private var reviewContactHeader: some View {
        HStack(spacing: DesignTokens.Spacing.medium) {
            reviewContactAvatar(size: 64)
            VStack(alignment: .leading, spacing: DesignTokens.Spacing.micro) {
                Text(nameText.isEmpty ? "Name" : nameText)
                    .font(.title3.weight(.semibold))
                    .foregroundStyle(.primary)
                if shouldShowEmailField {
                    Text(emailText)
                        .font(.subheadline)
                        .foregroundStyle(.secondary)
                }
            }
            Spacer()
        }
        .padding(.horizontal, DesignTokens.Spacing.medium)
        .padding(.vertical, DesignTokens.Spacing.small)
    }

    private var reviewContactImageData: Data? {
        selectedContact?.imageThumbData ?? souvenir?.primaryContact?.imageThumbData
    }

    private func reviewContactAvatar(size: CGFloat) -> some View {
        Group {
            if let data = reviewContactImageData,
               let image = UIImage(data: data) {
                Image(uiImage: image)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .frame(width: size, height: size)
                    .clipShape(Circle())
            }
        }
    }

    private var shouldShowEmailField: Bool {
        guard let contact = selectedContact else { return false }
        return !(contact.email?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
    }

    private var shouldShowAddressField: Bool {
        guard let contact = selectedContact else { return false }
        return !(contact.address?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
    }

    private var birthdayBinding: Binding<Date?> {
        Binding(
            get: { birthday },
            set: { birthday = $0 }
        )
    }

    private var giveSouvenirButton: some View {
        HStack {
            Spacer()
            Button {
                guard hasAttachedPhoto else { return }
                if isSelfie {
                    // Clear pending search before dismissing so it doesn't re-open
                    pendingContactSearch = false
                    completeSelfieSouvenir()
                } else {
                    // Clear pending search before dismissing so it doesn't re-open
                    pendingContactSearch = false
                    saveContactEdits()
                    prepareForShare()
                }
            } label : {
                HStack(spacing: DesignTokens.Spacing.small) {
                    Spacer()
                    Image(systemName: isSelfie ? "square.and.arrow.down.fill" : "square.and.arrow.up.fill")
                        .font(.title3.weight(.medium))
                        .symbolRenderingMode(.hierarchical)
                        .foregroundStyle(.primary)
                    Text(isSelfie ? "Save Souvenir" : "Share Souvenir")
                        .font(.title3.weight(.medium))
                        .foregroundStyle(.primary)
                    Spacer()
                }
                .padding(.horizontal, DesignTokens.Spacing.large)
                .padding(.vertical, DesignTokens.Spacing.medium)
            }
            .buttonStyle(.plain)
            .contentShape(Rectangle())
            .background(
                Color.successSvnr.opacity(DesignTokens.Opacity.healthy),
                in: Capsule()
            )
            .overlay(
                Capsule()
                    .strokeBorder(Color.successSvnr.opacity(0.4), lineWidth: 1)
            )
            Spacer()
        }
        .disabled(!hasAttachedPhoto)
        .listRowBackground(Color.successSvnr.opacity(DesignTokens.Opacity.light))
    }

    private var viewHeader: some View {
        HStack {
            Text(selectedContact?.displayName ?? "Untitled")
                .font(.title2.weight(.semibold))
            Spacer()
            NakedIconButton(systemName: "pencil") {
                contactDetailsMode = .review
            }
        }
    }

    private var viewDetails: some View {
        VStack(alignment: .leading, spacing: DesignTokens.Spacing.small) {
            if !phoneText.isEmpty {
                ContactInfoRow(systemImage: "phone", text: phoneText)
            }
            if !emailText.isEmpty {
                ContactInfoRow(systemImage: "envelope", text: emailText)
            }
        }
    }

    private var viewFooter: some View {
        PrimaryCtaButton(title: "Share") {
            guard hasAttachedPhoto else { return }
            saveContactEdits()
            prepareForShare()
        }
        .disabled(!hasAttachedPhoto)
    }

    private func saveContactEdits() {
        guard let souvenir else { return }
        guard let contact = selectedContact ?? souvenir.primaryContact else { return }
        let souvenirID = souvenir.objectID
        let contactID = contact.objectID
        viewContext.perform {
            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity,
                  let contactInContext = viewContext.object(with: contactID) as? ContactEntity else { return }

            contactInContext.compositeName = nameText
            contactInContext.givenName = nameText
            contactInContext.phoneE164 = phoneText
            contactInContext.email = emailText
            contactInContext.address = addressText
            contactInContext.birthday = birthday

            souvenirInContext.primaryContact = contactInContext
            souvenirInContext.isSelfie = isSelfie
            if isSelfie {
                SelfContactService.shared.setSelfContactOnContextQueue(contactID: contactInContext.id, in: viewContext)
            }

            // Ensure permanent IDs for souvenir, contact, and any photos before presenting share
            var objects: [NSManagedObject] = [souvenirInContext, contactInContext]
            for p in souvenirInContext.photosArray { objects.append(p) }
            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
            if !tempObjects.isEmpty {
                try? viewContext.obtainPermanentIDs(for: tempObjects)
            }
            try? viewContext.save()
        }
    }

    private func navigateToSouvenirIfReady() {
        guard let souvenir else { return }
        router.navigate(to: .souvenir(id: souvenir.id))
    }

    private func completeSelfieSouvenir() {
        saveContactEdits()
        if let souvenir {
            newSouvenirTracker.trackNewSouvenir(souvenir.id)
        }
        showContactDetails = false
        newSouvenirTracker.requestReturnToOrigin()
    }

    private func prepareForShare() {
        guard let souvenir else { return }
        let souvenirID = souvenir.objectID

        viewContext.perform {
            guard let souvenirInContext = self.viewContext.object(with: souvenirID) as? SouvenirEntity else { return }
            var objects: [NSManagedObject] = [souvenirInContext]
            if let contact = souvenirInContext.primaryContact { objects.append(contact) }
            for p in souvenirInContext.photosArray { objects.append(p) }

            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
            if !tempObjects.isEmpty {
                do {
                    try self.viewContext.obtainPermanentIDs(for: tempObjects)
                } catch {
                    print("❌ Failed to obtain permanent IDs: \(error)")
                    return
                }
            }

            do {
                try self.viewContext.save()
            } catch {
                print("❌ Failed to save before share: \(error)")
                return
            }

            // Dismiss sheets and call callback on main thread with fresh fetch from permanent ID
            DispatchQueue.main.async {
                self.showContactDetails = false
                if let persistentID = souvenirInContext.objectID as NSManagedObjectID?,
                   !persistentID.isTemporaryID,
                   let refreshedSouvenir = self.viewContext.object(with: persistentID) as? SouvenirEntity {
                    self.onReadyToShare?(refreshedSouvenir)
                }
            }
        }
    }
}

