   341→    /// Save captured image to Documents/LocalCaptures and return a local:// identifier
   342→    private static func saveCapturedImageToDocuments(_ image: UIImage) throws -> String {
   343→        guard let data = image.jpegData(compressionQuality: 0.92) else {
   344→            throw NSError(domain: "SouvenirApp", code: -1, userInfo: [NSLocalizedDescriptionKey: "Could not encode image as JPEG"])
   345→        }
   346→
   347→        let documentsURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
   348→        let capturesURL = documentsURL.appendingPathComponent("LocalCaptures", isDirectory: true)
   349→        try FileManager.default.createDirectory(at: capturesURL, withIntermediateDirectories: true)
   350→
   351→        let filename = "capture-\(UUID().uuidString).jpg"
   352→        let fileURL = capturesURL.appendingPathComponent(filename)
   353→        try data.write(to: fileURL, options: [.atomic])
   354→
   355→        return "local://\(filename)"
   356→    }
