   531→    private func selectContactResult(_ result: ContactSearchResult) {
   532→        Task {
   533→            let contact: ContactEntity?
   534→            let displayPhone: String?
   535→            let displayEmail: String?
   536→            var displayBirthday: Date?
   537→            switch result {
   538→            case .local(let existing):
   539→                displayBirthday = existing.birthday
   540→                if existing.birthday == nil,
   541→                   ContactsSystemService().authorizationStatus() == .authorized {
   542→                    if let externalIdentifier = existing.externalIdentifier,
   543→                       let cnContact = try? await ContactsSystemService().fetchContact(identifier: externalIdentifier),
   544→                       let refreshed = try? await contactService.importSystemContact(cnContact) {
   545→                        contact = refreshed
   546→                        displayPhone = refreshed.phoneE164
   547→                        displayEmail = refreshed.email
   548→                        // Use system contact's birthday if available
   549→                        if refreshed.birthday == nil, let systemBirthdayComponents = cnContact.birthday,
   550→                           let systemBirthday = Calendar.current.date(from: systemBirthdayComponents) {
   551→                            displayBirthday = systemBirthday
   552→                        }
   553→                    } else {
   554→                        let query = existing.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
   555→                        if !query.isEmpty,
   556→                           let candidates = try? await ContactsSystemService().searchContacts(query: query) {
   557→                            let targetPhone = (existing.phoneE164 ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
   558→                            let targetEmail = (existing.email ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
   559→                            let match = candidates.first { candidate in
   560→                                if !targetEmail.isEmpty, candidate.emailAddresses.contains(where: { ($0.value as String).caseInsensitiveCompare(targetEmail) == .orderedSame }) {
   561→                                    return true
   562→                                }
   563→                                if !targetPhone.isEmpty {
   564→                                    let normalizer = ContactSearchNormalizer()
   565→                                    return candidate.phoneNumbers.contains(where: { normalizer.normalizePhone(input: $0.value.stringValue) == targetPhone })
   566→                                }
   567→                                return false
   568→                            } ?? candidates.first
   569→                            if let match,
   570→                               let refreshed = try? await contactService.importSystemContact(match) {
   571→                                contact = refreshed
   572→                                displayPhone = refreshed.phoneE164
   573→                                displayEmail = refreshed.email
   574→                                // Use system contact's birthday if available
   575→                                if refreshed.birthday == nil, let systemBirthdayComponents = match.birthday,
   576→                                   let systemBirthday = Calendar.current.date(from: systemBirthdayComponents) {
   577→                                    displayBirthday = systemBirthday
   578→                                }
   579→                            } else {
   580→                                contact = existing
   581→                                displayPhone = existing.phoneE164
   582→                                displayEmail = existing.email
   583→                            }
   584→                        } else {
   585→                            contact = existing
   586→                            displayPhone = existing.phoneE164
   587→                            displayEmail = existing.email
   588→                        }
   589→                    }
   590→                } else {
   591→                    contact = existing
   592→                    displayPhone = existing.phoneE164
   593→                    displayEmail = existing.email
   594→                }
   595→            case .system(let cnContact):
   596→                let rawPhone = cnContact.phoneNumbers.first?.value.stringValue
   597→                let rawEmail = cnContact.emailAddresses.first?.value as String?
   598→                let systemBirthdayComponents = cnContact.birthday
   599→                let systemBirthdayStr = systemBirthdayComponents.flatMap { Calendar.current.date(from: $0) }?.formatted(date: .abbreviated, time: .omitted) ?? "nil"
   600→                print("📱 System contact raw data:")
   601→                print("  rawPhone: \(rawPhone ?? "nil")")
   602→                print("  rawEmail: \(rawEmail ?? "nil")")
   603→                print("  cnContact.birthday: \(systemBirthdayStr)")
   604→                contact = try? await contactService.importSystemContact(cnContact)
   605→                displayPhone = rawPhone ?? contact?.phoneE164
   606→                displayEmail = rawEmail ?? contact?.email
   607→                displayBirthday = contact?.birthday ?? (systemBirthdayComponents.flatMap { Calendar.current.date(from: $0) })
   608→                if displayBirthday != nil {
   609→                    print("  ✅ Birthday set to: \(displayBirthday!.formatted(date: .abbreviated, time: .omitted))")
   610→                } else {
   611→                    print("  ⚠️ No birthday available from import or system contact")
   612→                }
   613→            case .new(let name):
   614→                let parts = name.split(separator: " ")
   615→                let given = parts.first.map(String.init)
   616→                let family = parts.dropFirst().joined(separator: " ")
   617→                contact = try? await contactService.createContact(givenName: given, familyName: family.isEmpty ? nil : family, phone: nil, email: nil)
   618→                displayPhone = nil
   619→                displayEmail = nil
   620→                displayBirthday = nil
   621→            }
   622→
   623→            await MainActor.run {
   624→                selectedContact = contact
   625→                nameText = contact?.displayName ?? result.displayName
   626→                phoneText = displayPhone ?? ""
   627→                emailText = displayEmail ?? ""
   628→                addressText = contact?.address ?? ""
   629→                birthday = displayBirthday
   630→                isSelfie = contact == nil ? false : (souvenir?.isSelfie ?? false)
   631→
   632→                // Log contact population for debugging
   633→                print("📋 Contact populated:")
   634→                print("  name: \(nameText)")
   635→                print("  phone: \(phoneText)")
   636→                print("  email: \(emailText)")
   637→                print("  address: \(addressText)")
   638→                print("  birthday: \(displayBirthday?.formatted(date: .abbreviated, time: .omitted) ?? "nil")")
   639→
   640→                // Dismissing ContactReviewSheet will re-show ContactSearchSheet
   641→                suppressRetakeOnDismiss = true
   642→                showContactSearch = false
   643→                pendingContactSearch = true
   644→                contactDetailsMode = .review
   645→                showContactDetails = true
   646→            }
   647→
   648→            // Persist selected contact as the souvenir's primary contact.
   649→            if let contact {
   650→                let contactID = contact.objectID
   651→                if let souvenir {
   652→                    let souvenirID = souvenir.objectID
   653→                    await viewContext.perform {
   654→                        guard let contactInContext = viewContext.object(with: contactID) as? ContactEntity,
   655→                              let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else {
   656→                            return
   657→                        }
   658→                        contactInContext.isPrimaryForSouvenir = true
   659→                        souvenirInContext.primaryContact = contactInContext
   660→                        try? viewContext.save()
   661→                    }
   662→                }
   663→            }
   664→        }
   665→    }
