   841→    private func saveContactEdits() {
   842→        guard let souvenir else { return }
   843→        guard let contact = selectedContact ?? souvenir.primaryContact else { return }
   844→        let souvenirID = souvenir.objectID
   845→        let contactID = contact.objectID
   846→        viewContext.perform {
   847→            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity,
   848→                  let contactInContext = viewContext.object(with: contactID) as? ContactEntity else { return }
   849→
   850→            contactInContext.compositeName = nameText
   851→            contactInContext.givenName = nameText
   852→            contactInContext.phoneE164 = phoneText
   853→            contactInContext.email = emailText
   854→            contactInContext.address = addressText
