   864→            var objects: [NSManagedObject] = [souvenirInContext, contactInContext]
   865→            for p in souvenirInContext.photosArray { objects.append(p) }
   866→            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
   867→            if !tempObjects.isEmpty {
