   888→    private func prepareForShare() {
   889→        guard let souvenir else { return }
   890→        let souvenirID = souvenir.objectID
   891→
   892→        viewContext.perform {
   893→            guard let souvenirInContext = self.viewContext.object(with: souvenirID) as? SouvenirEntity else { return }
   894→            var objects: [NSManagedObject] = [souvenirInContext]
   895→            if let contact = souvenirInContext.primaryContact { objects.append(contact) }
   896→            for p in souvenirInContext.photosArray { objects.append(p) }
   897→
   898→            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
   899→            if !tempObjects.isEmpty {
   900→                do {
   901→                    try self.viewContext.obtainPermanentIDs(for: tempObjects)
   902→                } catch {
   903→                    print("❌ Failed to obtain permanent IDs: \(error)")
   904→                    return
   905→                }
   906→            }
   907→
   908→            do {
   909→                try self.viewContext.save()
   910→            } catch {
   911→                print("❌ Failed to save before share: \(error)")
   912→                return
   913→            }
   914→
   915→            // Dismiss sheets and call callback on main thread with fresh fetch from permanent ID
   916→            DispatchQueue.main.async {
   917→                self.showContactDetails = false
   918→                if let persistentID = souvenirInContext.objectID as NSManagedObjectID?,
   919→                   !persistentID.isTemporaryID,
   920→                   let refreshedSouvenir = self.viewContext.object(with: persistentID) as? SouvenirEntity {
