   375→    private func validatePhone(_ value: String) {
   376→        guard !value.isEmpty else {
   377→            phoneError = nil
   378→            return
   379→        }
   380→
   381→        let normalizer = ContactSearchNormalizer()
   382→        if let _ = normalizer.normalizePhone(input: value) {
   383→            phoneError = nil
   384→        } else {
   385→            phoneError = phoneHintText
   386→        }
   387→    }
   388→
   389→    private func normalizedPhoneDigits(from input: String) -> String {
   390→        let digits = input.filter(\.isNumber)
   391→        guard !digits.isEmpty else { return "" }
   392→        if digits.first == "1" {
   393→            return String(digits.prefix(11))
   394→        }
   395→        return String(digits.prefix(10))
   396→    }
   397→
   398→    private func formattedPhone(_ input: String) -> String {
   399→        let digits = normalizedPhoneDigits(from: input)
   400→        guard !digits.isEmpty else { return "" }
   401→
   402→        // US/CA country code '1': format as (NXX) NXX-XXXX, no +1 prefix
   403→        var rest = digits
   404→        if rest.first == "1" {
   405→            rest = String(rest.dropFirst())
   406→        }
   407→
   408→        let area = String(rest.prefix(3))
   409→        let remainderAfterArea = String(rest.dropFirst(min(3, rest.count)))
   410→        let prefix = String(remainderAfterArea.prefix(3))
   411→        let line = String(remainderAfterArea.dropFirst(min(3, remainderAfterArea.count)).prefix(4))
   412→
   413→        var result = ""
   414→
   415→        if !area.isEmpty {
   416→            result += "(\(area)"
   417→            if area.count == 3 { result += ")" }
   418→        }
   419→
   420→        if !prefix.isEmpty {
   421→            if area.count == 3 { result += " " }
   422→            result += prefix
   423→        }
   424→
   425→        if !line.isEmpty {
   426→            result += "-\(line)"
   427→        }
   428→
   429→        return result
   430→    }
