    /// Persist all contact edits and photos in one context.perform block, then call back with
    /// the souvenir once it has a permanent ID. Keeping everything in a single perform block
    /// eliminates the stale-temporary-ID race that arises when saveContactEdits() and a
    /// separate prepareForShare() each capture objectID before the first save promotes temp IDs.
    @MainActor
    private func saveAndShare() async {
        guard let souvenir else { return }
        guard let contact = selectedContact ?? souvenir.primaryContact else { return }

        // Capture all values and IDs on the main thread before entering perform.
        let souvenirID = souvenir.objectID
        let contactID = contact.objectID
        let nameSnapshot = nameText
        let phoneSnapshot = phoneText
        let emailSnapshot = emailText
        let addressSnapshot = addressText
        let birthdaySnapshot = birthday
        let isSelfieSnapshot = isSelfie

        let permanentSouvenirID: NSManagedObjectID? = await viewContext.perform {
            guard let souvenirInContext = self.viewContext.object(with: souvenirID) as? SouvenirEntity,
                  let contactInContext = self.viewContext.object(with: contactID) as? ContactEntity else {
                return nil
            }

            // Write all edits.
            contactInContext.compositeName = nameSnapshot
            contactInContext.givenName = nameSnapshot
            contactInContext.phoneE164 = phoneSnapshot
            contactInContext.email = emailSnapshot
            contactInContext.address = addressSnapshot
            contactInContext.birthday = birthdaySnapshot

            souvenirInContext.primaryContact = contactInContext
            souvenirInContext.isSelfie = isSelfieSnapshot
            if isSelfieSnapshot {
                SelfContactService.shared.setSelfContactOnContextQueue(contactID: contactInContext.id, in: self.viewContext)
            }

            // Promote every temp ID in one shot before saving.
            var objects: [NSManagedObject] = [souvenirInContext, contactInContext]
            for p in souvenirInContext.photosArray { objects.append(p) }
            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
            if !tempObjects.isEmpty {
                do {
                    try self.viewContext.obtainPermanentIDs(for: tempObjects)
                } catch {
                    print("❌ obtainPermanentIDs failed: \(error)")
                    return nil
                }
            }

            do {
                try self.viewContext.save()
            } catch {
                print("❌ save failed before share: \(error)")
                return nil
            }

            // After save, the objectID is now permanent — return it so the main actor can fetch.
            return souvenirInContext.objectID
        }

        // Back on MainActor: dismiss and invoke share callback.
        showContactDetails = false
        guard let permanentID = permanentSouvenirID,
              !permanentID.isTemporaryID,
              let refreshed = viewContext.object(with: permanentID) as? SouvenirEntity else {
            print("❌ Could not obtain permanent souvenir after save")
            return
        }
        onReadyToShare?(refreshed)
    }

    /// Persist all contact edits in one context.perform block (selfie path — no share callback).
    @MainActor
    private func saveContactEditsAsync() async {
        guard let souvenir else { return }
        guard let contact = selectedContact ?? souvenir.primaryContact else { return }

        let souvenirID = souvenir.objectID
        let contactID = contact.objectID
        let nameSnapshot = nameText
        let phoneSnapshot = phoneText
        let emailSnapshot = emailText
        let addressSnapshot = addressText
        let birthdaySnapshot = birthday
        let isSelfieSnapshot = isSelfie

        await viewContext.perform {
            guard let souvenirInContext = self.viewContext.object(with: souvenirID) as? SouvenirEntity,
                  let contactInContext = self.viewContext.object(with: contactID) as? ContactEntity else { return }

            contactInContext.compositeName = nameSnapshot
            contactInContext.givenName = nameSnapshot
            contactInContext.phoneE164 = phoneSnapshot
            contactInContext.email = emailSnapshot
            contactInContext.address = addressSnapshot
            contactInContext.birthday = birthdaySnapshot

            souvenirInContext.primaryContact = contactInContext
            souvenirInContext.isSelfie = isSelfieSnapshot
            if isSelfieSnapshot {
                SelfContactService.shared.setSelfContactOnContextQueue(contactID: contactInContext.id, in: self.viewContext)
            }

            var objects: [NSManagedObject] = [souvenirInContext, contactInContext]
            for p in souvenirInContext.photosArray { objects.append(p) }
            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
            if !tempObjects.isEmpty {
                try? self.viewContext.obtainPermanentIDs(for: tempObjects)
            }
            try? self.viewContext.save()
        }
    }

    private func navigateToSouvenirIfReady() {
        guard let souvenir else { return }
        router.navigate(to: .souvenir(id: souvenir.id))
    }

    private func completeSelfieSouvenir() {
        Task {
            await saveContactEditsAsync()
            if let souvenir {
                newSouvenirTracker.trackNewSouvenir(souvenir.id)
            }
            showContactDetails = false
            newSouvenirTracker.requestReturnToOrigin()
        }
    }
}

