   306→
   307→        let imageOptions = PHImageRequestOptions()
   308→        imageOptions.isSynchronous = false
   309→        imageOptions.deliveryMode = .opportunistic
   310→        imageOptions.resizeMode = .fast
   311→
   312→        let targetSize = CGSize(width: 80, height: 80)
   313→
   314→        PHImageManager.default().requestImage(
   315→            for: asset,
   316→            targetSize: targetSize,
   317→            contentMode: .aspectFill,
   318→            options: imageOptions
   319→        ) { image, _ in
   320→            if let image = image {
   321→                Task { @MainActor in
   322→                    recentPhotoThumbnail = image
