   375→@MainActor
   376→class CameraController: NSObject, ObservableObject {
   377→    let session = AVCaptureSession()
   378→    private let videoOutput = AVCaptureVideoDataOutput()
   379→    private var currentCamera: AVCaptureDevice?
   380→    private var frameBuffer: [UIImage] = []
   381→    private let maxBufferSize = 20  // Pre-capture frames (~0.67s at 30fps)
   382→    private var postTapFrames: [UIImage] = []
   383→    private var isCapturingPostTap = false
   384→    private var postTapTarget = 5  // Frames to capture after tap
   385→    private var burstCompletion: ((UIImage) -> Void)?
   386→    @Published var isLowLight = false
   387→    @Published var capturedImage: UIImage?
   388→    private var averageBrightness: Double = 0.5
   389→    private let analyzer = ServicesFrameQualityAnalyzer()
   390→    private let sessionID = UUID().uuidString
   391→    private var hasStopped = false  // Prevent redundant stop calls
   392→    private let videoQueue = DispatchQueue(label: "com.souvenir.videoCapture")
   393→    private let ciContext = CIContext()
   394→
   395→    @Published var flashMode: AVCaptureDevice.FlashMode = .off
   396→    @Published var cameraPosition: AVCaptureDevice.Position = .front
   397→    @Published var isAnalyzing = false
