   399→    override init() {
   400→        super.init()
   401→        setupSession()
   402→        print("📹 CameraController[\(sessionID)] initialized")
   403→    }
   404→    
   405→    deinit {
   406→        print("📹 CameraController[\(sessionID)] deinitialized")
   407→        // Note: Cannot call main actor-isolated methods from deinit
   408→        // Session cleanup is handled by stopSession() which is called before dismissal
   409→    }
   410→    
   411→    private func setupSession() {
   412→        session.beginConfiguration()
   413→
   414→        // Set preset
   415→        if session.canSetSessionPreset(.photo) {
   416→            session.sessionPreset = .photo
   417→        }
   418→
   419→        // Add camera input (front camera by default)
   420→        if let camera = getCamera(for: .front) {
   421→            do {
   422→                let input = try AVCaptureDeviceInput(device: camera)
   423→                if session.canAddInput(input) {
   424→                    session.addInput(input)
   425→                    currentCamera = camera
   426→                }
   427→            } catch {
   428→                print("❌ Failed to add camera input: \(error)")
   429→            }
   430→        }
   431→
   432→        // Add video data output (silent frame capture)
   433→        videoOutput.setSampleBufferDelegate(self, queue: videoQueue)
   434→        videoOutput.alwaysDiscardsLateVideoFrames = true
   435→        if session.canAddOutput(videoOutput) {
   436→            session.addOutput(videoOutput)
   437→
   438→            // Configure output
   439→            if let connection = videoOutput.connection(with: .video) {
   440→                if connection.isVideoMirroringSupported {
   441→                    connection.isVideoMirrored = (cameraPosition == .front)
   442→                }
   443→                if connection.isVideoRotationAngleSupported(90) {
   444→                    connection.videoRotationAngle = 90
   445→                }
   446→            }
   447→        }
   448→
   449→        session.commitConfiguration()
   450→    }
   451→    
   452→    nonisolated func startSession() {
   453→        Task.detached { [weak self] in
   454→            guard let self = self else { return }
   455→            await self.session.startRunning()
   456→            await MainActor.run {
   457→                print("📹 CameraController[\(self.sessionID)] session STARTED (isRunning: \(self.session.isRunning))")
   458→                CameraStateMonitor.shared.registerSession(self.sessionID)
   459→            }
   460→        }
   461→    }
   462→    
   463→    func stopSession() {
   464→        // Guard against redundant stop calls (from capture, dismiss, disappear, deinit)
   465→        guard !hasStopped else {
   466→            return
   467→        }
   468→        hasStopped = true
   469→
   470→        // Turn off torch before stopping
   471→        setTorchMode(.off)
   472→
   473→        // Stop synchronously to ensure camera resources are released immediately
   474→        // This prevents resource contention when text input needs to initialize
   475→        print("📹 CameraController[\(sessionID)] stopSession() called (isRunning: \(session.isRunning))")
   476→
   477→        if session.isRunning {
   478→            session.stopRunning()
   479→        }
   480→
   481→        CameraStateMonitor.shared.unregisterSession(sessionID)
   482→        print("🎥 Camera session stopped for \(sessionID)")
   483→    }
   484→    
   485→    func flipCamera() {
   486→        // Turn off torch on current camera before switching
   487→        setTorchMode(.off)
   488→        flashMode = .off
   489→
   490→        let newPosition: AVCaptureDevice.Position = (cameraPosition == .front) ? .back : .front
   491→
   492→        guard let newCamera = getCamera(for: newPosition) else {
   493→            print("⚠️ Camera not available for position: \(newPosition.rawValue)")
   494→            return
   495→        }
   496→
   497→        session.beginConfiguration()
   498→
   499→        // Remove current input
   500→        if let currentInput = session.inputs.first as? AVCaptureDeviceInput {
   501→            session.removeInput(currentInput)
   502→        }
   503→
   504→        // Add new input
   505→        do {
   506→            let newInput = try AVCaptureDeviceInput(device: newCamera)
   507→            if session.canAddInput(newInput) {
   508→                session.addInput(newInput)
   509→                currentCamera = newCamera
   510→                cameraPosition = newPosition
   511→
   512→                // Update mirroring for front camera
   513→                if let connection = videoOutput.connection(with: .video),
   514→                   connection.isVideoMirroringSupported {
   515→                    connection.isVideoMirrored = (newPosition == .front)
   516→                }
   517→            }
   518→        } catch {
   519→            print("❌ Failed to flip camera: \(error)")
   520→        }
   521→
   522→        session.commitConfiguration()
   523→    }
   524→    
   525→    func toggleFlash() {
   526→        // Only allow flash on back camera (torch is only available on back)
   527→        guard cameraPosition == .back else { return }
   528→
   529→        switch flashMode {
   530→        case .off:
   531→            flashMode = .on
   532→            setTorchMode(.on)
   533→        case .on:
   534→            flashMode = .auto
   535→            setTorchMode(.off)
   536→        case .auto:
   537→            flashMode = .off
   538→            setTorchMode(.off)
   539→        @unknown default:
   540→            flashMode = .off
   541→            setTorchMode(.off)
   542→        }
   543→    }
   544→
   545→    private func setTorchMode(_ mode: AVCaptureDevice.TorchMode) {
   546→        guard let device = currentCamera, device.hasTorch else { return }
   547→        do {
   548→            try device.lockForConfiguration()
   549→            device.torchMode = mode
   550→            device.unlockForConfiguration()
   551→        } catch {
   552→            print("❌ Failed to set torch mode: \(error)")
   553→        }
   554→    }
   555→    
   556→    func captureBurst(completion: @escaping (UIImage) -> Void) {
   557→        // Grab the last 20 pre-captured frames + collect 5 new frames after tap
   558→        let preFrames = Array(frameBuffer.suffix(20))
   559→        guard !preFrames.isEmpty else {
   560→            print("⚠️ No frames in buffer yet")
   561→            completion(UIImage())
   562→            return
   563→        }
   564→
   565→        // Immediate haptic + shutter sound feedback
   566→        let impact = UIImpactFeedbackGenerator(style: .medium)
   567→        impact.impactOccurred()
   568→        playShutterSound()
   569→
   570→        postTapFrames = []
   571→        isCapturingPostTap = true
   572→        isAnalyzing = true
   573→        burstCompletion = completion
   574→        print("📸 Captured 40 pre-tap frames, collecting 5 post-tap...")
   575→    }
   576→
   577→    private func playShutterSound() {
   578→        let soundID: SystemSoundID = 1108  // iOS camera shutter sound ID
   579→        AudioServicesPlaySystemSound(soundID)
   580→    }
   581→
   582→    private nonisolated func calculateBrightness(_ image: UIImage) -> Double {
   583→        guard let cgImage = image.cgImage else { return 0.5 }
   584→        let w = min(cgImage.width, 64), h = min(cgImage.height, 64)
   585→        let bytesPerPixel = 4
   586→        var pixels = [UInt8](repeating: 0, count: w * h * bytesPerPixel)
   587→        let colorSpace = CGColorSpaceCreateDeviceRGB()
   588→        guard let ctx = CGContext(data: &pixels, width: w, height: h,
   589→                                  bitsPerComponent: 8, bytesPerRow: w * bytesPerPixel,
   590→                                  space: colorSpace,
   591→                                  bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else { return 0.5 }
   592→        ctx.draw(cgImage, in: CGRect(x: 0, y: 0, width: w, height: h))
   593→        let luminances = stride(from: 0, to: pixels.count, by: bytesPerPixel).map { i -> Double in
   594→            0.299 * Double(pixels[i]) + 0.587 * Double(pixels[i+1]) + 0.114 * Double(pixels[i+2])
   595→        }
   596→        return luminances.isEmpty ? 0.5 : luminances.reduce(0, +) / Double(luminances.count) / 255.0
   597→    }
   598→    
   599→    private func getCamera(for position: AVCaptureDevice.Position) -> AVCaptureDevice? {
   600→        // Try to get the best camera for the position
   601→        if let device = AVCaptureDevice.default(.builtInWideAngleCamera, for: .video, position: position) {
   602→            return device
   603→        }
   604→        
   605→        // Fallback to any camera in that position using AVCaptureDeviceDiscoverySession
   606→        let discoverySession = AVCaptureDevice.DiscoverySession(
   607→            deviceTypes: [.builtInWideAngleCamera, .builtInTelephotoCamera, .builtInUltraWideCamera],
   608→            mediaType: .video,
   609→            position: position
   610→        )
   611→        return discoverySession.devices.first
   612→    }
   613→}
