   615→// MARK: - Video Capture Delegate
   616→
   617→extension CameraController: AVCaptureVideoDataOutputSampleBufferDelegate {
   618→    nonisolated func captureOutput(
   619→        _ output: AVCaptureOutput,
   620→        didOutput sampleBuffer: CMSampleBuffer,
   621→        from connection: AVCaptureConnection
   622→    ) {
   623→        guard let pixelBuffer = CMSampleBufferGetImageBuffer(sampleBuffer) else { return }
   624→
   625→        // Render pixel buffer to actual UIImage with pixel data
   626→        let ciImage = CIImage(cvPixelBuffer: pixelBuffer)
   627→        guard let cgImage = self.ciContext.createCGImage(ciImage, from: ciImage.extent) else { return }
   628→        let image = UIImage(cgImage: cgImage)
   629→
   630→        Task { @MainActor in
   631→            // Maintain rolling buffer of last 20 pre-capture frames
   632→            self.frameBuffer.append(image)
   633→            if self.frameBuffer.count > self.maxBufferSize {
   634→                self.frameBuffer.removeFirst()
   635→            }
   636→
   637→            // Track brightness for low-light glow
   638→            self.averageBrightness = self.calculateBrightness(image)
   639→            self.isLowLight = self.averageBrightness < 0.3
   640→
   641→            // If capturing post-tap, also collect frames after the tap
   642→            if self.isCapturingPostTap {
   643→                self.postTapFrames.append(image)
   644→                if self.postTapFrames.count >= self.postTapTarget {
   645→                    self.isCapturingPostTap = false
   646→                    // Combine 20 pre-tap + 5 post-tap frames
   647→                    let preFrames = Array(self.frameBuffer.suffix(20))
   648→                    var allFrames = preFrames
   649→                    allFrames.append(contentsOf: self.postTapFrames)
   650→                    let completion = self.burstCompletion
   651→                    self.postTapFrames = []
   652→                    self.burstCompletion = nil
   653→
   654→                    print("📸 Analyzing \(allFrames.count) frames (20 pre + 5 post)...")
   655→                    Task.detached { [weak self] in
   656→                        guard let self else { return }
   657→                        let best = await self.analyzer.bestFrame(from: allFrames)
   658→                        await MainActor.run {
   659→                            self.stopSession()  // Stop camera immediately
   660→                            self.isAnalyzing = false
   661→                            // Haptic feedback when analysis complete
   662→                            let success = UINotificationFeedbackGenerator()
   663→                            success.notificationOccurred(.success)
   664→                            print("📸 Best frame selected")
   665→                            completion?(best)
   666→                        }
   667→                    }
   668→                }
   669→            }
   670→        }
   671→    }
   672→}
