   674→// MARK: - Camera Location Manager
   675→
   676→/// Lightweight location manager to request permission when camera opens
   677→/// This ensures location is available when the photo is captured
   678→@MainActor
   679→class CameraLocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
   680→    private let manager = CLLocationManager()
   681→    
   682→    /// Current location (if available)
   683→    @Published var location: CLLocation?
   684→    private var pendingContinuations: [CheckedContinuation<CLLocation?, Never>] = []
   685→    private var timeoutTask: Task<Void, Never>?
   686→    private var isRequestingLocation = false
   687→
   688→    override init() {
   689→        super.init()
   690→        manager.delegate = self
   691→        manager.desiredAccuracy = kCLLocationAccuracyBest
   692→    }
   693→
   694→    func requestPermissionIfNeeded(promptIfNeeded: Bool = true) {
   695→        let status = manager.authorizationStatus
   696→        if status == .notDetermined {
   697→            if promptIfNeeded {
   698→                manager.requestWhenInUseAuthorization()
   699→            }
   700→        } else if status == .authorizedWhenInUse || status == .authorizedAlways {
   701→            manager.startUpdatingLocation()
   702→        }
   703→    }
   704→
   705→    /// Await a location update with a timeout (returns nil if not authorized or timed out).
   706→    func awaitCurrentLocation(timeout: TimeInterval) async -> CLLocation? {
   707→        let start = Date()
   708→        var status = manager.authorizationStatus
   709→
   710→        if status == .notDetermined {
   711→            manager.requestWhenInUseAuthorization()
   712→            while status == .notDetermined,
   713→                  Date().timeIntervalSince(start) < timeout {
   714→                try? await Task.sleep(for: .milliseconds(150))
   715→                status = manager.authorizationStatus
   716→            }
   717→        }
   718→
   719→        guard status == .authorizedWhenInUse || status == .authorizedAlways else {
   720→            return location
   721→        }
   722→        if let location = location, abs(location.timestamp.timeIntervalSinceNow) < 30 {
   723→            return location
   724→        }
   725→
   726→        let elapsed = Date().timeIntervalSince(start)
   727→        let remaining = max(0.1, timeout - elapsed)
   728→        return await withCheckedContinuation { continuation in
   729→            Task { @MainActor in
   730→                enqueueContinuation(continuation, timeout: remaining)
   731→            }
   732→        }
   733→    }
   734→
   735→    @MainActor
   736→    private func enqueueContinuation(_ continuation: CheckedContinuation<CLLocation?, Never>, timeout: TimeInterval) {
   737→        pendingContinuations.append(continuation)
   738→
   739→        guard !isRequestingLocation else { return }
   740→        isRequestingLocation = true
   741→        manager.startUpdatingLocation()
   742→
   743→        timeoutTask?.cancel()
   744→        timeoutTask = Task { @MainActor in
   745→            try? await Task.sleep(for: .seconds(timeout))
   746→            if !pendingContinuations.isEmpty {
   747→                resolvePending(with: nil)
   748→            }
   749→        }
   750→    }
   751→
   752→    @MainActor
   753→    private func resolvePending(with location: CLLocation?) {
   754→        let continuations = pendingContinuations
   755→        pendingContinuations.removeAll()
   756→        isRequestingLocation = false
   757→        timeoutTask?.cancel()
   758→        timeoutTask = nil
   759→        manager.stopUpdatingLocation()
   760→        continuations.forEach { $0.resume(returning: location) }
   761→    }
   762→
   763→    nonisolated func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
   764→        Task { @MainActor in
   765→            let status = manager.authorizationStatus
   766→            if status == .authorizedWhenInUse || status == .authorizedAlways {
   767→                manager.startUpdatingLocation()
   768→            }
   769→        }
   770→    }
   771→    
   772→    nonisolated func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
   773→        Task { @MainActor in
   774→            self.location = locations.last
   775→            resolvePending(with: locations.last)
   776→        }
   777→    }
   778→
   779→    nonisolated func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
   780→        print("❌ Location manager error: \(error.localizedDescription)")
   781→        Task { @MainActor in
   782→            resolvePending(with: nil)
   783→        }
   784→    }
   785→}
