   481→    private func computeResultsToShow() -> (trimmed: String, results: [ContactSearchResult]) {
   482→        let trimmed = contactQuery.trimmingCharacters(in: .whitespacesAndNewlines)
   483→        // Sort: contacts with phone numbers first, then by relevance (original order preserved within groups)
   484→        let sorted = contactResults.sorted { a, b in
   485→            let aHasPhone = resultHasPhone(a)
   486→            let bHasPhone = resultHasPhone(b)
   487→            if aHasPhone != bHasPhone { return aHasPhone }
   488→            return false  // stable: preserve relative order within each group
   489→        }
   490→        var resultsToShow = Array(sorted.prefix(7))
   491→        if resultsToShow.isEmpty, !trimmed.isEmpty {
   492→            resultsToShow = [.new(trimmed)]
   493→        }
   494→        return (trimmed, resultsToShow)
   495→    }
   496→
   497→    private func resultHasPhone(_ result: ContactSearchResult) -> Bool {
   498→        switch result {
   499→        case .local(let contact): return !(contact.phoneE164?.isEmpty ?? true)
   500→        case .system(let cn): return !cn.phoneNumbers.isEmpty
   501→        case .new: return false
   502→        }
   503→    }
   504→
   505→    private func triggerContactSearch(for query: String) {
   506→        searchTask?.cancel()
   507→        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
   508→        guard trimmed.count >= 1 else {
   509→            contactResults = []
   510→            isSearching = false
   511→            return
   512→        }
   513→
   514→        searchTask = Task {
   515→            await MainActor.run { isSearching = true }
   516→            do {
   517→                let results = try await contactService.searchAllContacts(query: trimmed, includeSystem: true)
   518→                await MainActor.run {
   519→                    contactResults = results
   520→                    isSearching = false
   521→                }
   522→            } catch {
   523→                await MainActor.run {
   524→                    contactResults = []
   525→                    isSearching = false
   526→                }
   527→            }
   528→        }
   529→    }
