   838→    /// Persist all contact edits and photos in one context.perform block, then call back with
   839→    /// the souvenir once it has a permanent ID. Keeping everything in a single perform block
   840→    /// eliminates the stale-temporary-ID race that arises when saveContactEdits() and a
   841→    /// separate prepareForShare() each capture objectID before the first save promotes temp IDs.
   842→    @MainActor
   843→    private func saveAndShare() async {
   844→        guard let souvenir else { return }
   845→        guard let contact = selectedContact ?? souvenir.primaryContact else { return }
   846→
   847→        // Capture all values and IDs on the main thread before entering perform.
   848→        let souvenirID = souvenir.objectID
   849→        let contactID = contact.objectID
   850→        let nameSnapshot = nameText
   851→        let phoneSnapshot = phoneText
   852→        let emailSnapshot = emailText
   853→        let addressSnapshot = addressText
   854→        let birthdaySnapshot = birthday
   855→        let isSelfieSnapshot = isSelfie
   856→
   857→        let permanentSouvenirID: NSManagedObjectID? = await viewContext.perform {
   858→            guard let souvenirInContext = self.viewContext.object(with: souvenirID) as? SouvenirEntity,
   859→                  let contactInContext = self.viewContext.object(with: contactID) as? ContactEntity else {
   860→                return nil
   861→            }
   862→
   863→            // Write all edits.
   864→            contactInContext.compositeName = nameSnapshot
   865→            contactInContext.givenName = nameSnapshot
   866→            contactInContext.phoneE164 = phoneSnapshot
   867→            contactInContext.email = emailSnapshot
   868→            contactInContext.address = addressSnapshot
   869→            contactInContext.birthday = birthdaySnapshot
   870→
   871→            souvenirInContext.primaryContact = contactInContext
   872→            souvenirInContext.isSelfie = isSelfieSnapshot
   873→            if isSelfieSnapshot {
   874→                SelfContactService.shared.setSelfContactOnContextQueue(contactID: contactInContext.id, in: self.viewContext)
   875→            }
   876→
   877→            // Promote every temp ID in one shot before saving.
   878→            var objects: [NSManagedObject] = [souvenirInContext, contactInContext]
   879→            for p in souvenirInContext.photosArray { objects.append(p) }
   880→            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
   881→            if !tempObjects.isEmpty {
   882→                do {
   883→                    try self.viewContext.obtainPermanentIDs(for: tempObjects)
   884→                } catch {
   885→                    print("❌ obtainPermanentIDs failed: \(error)")
   886→                    return nil
   887→                }
   888→            }
   889→
   890→            do {
   891→                try self.viewContext.save()
   892→            } catch {
   893→                print("❌ save failed before share: \(error)")
   894→                return nil
   895→            }
   896→
   897→            // After save, the objectID is now permanent — return it so the main actor can fetch.
   898→            return souvenirInContext.objectID
   899→        }
   900→
   901→        // Back on MainActor: dismiss and invoke share callback.
   902→        showContactDetails = false
   903→        guard let permanentID = permanentSouvenirID,
   904→              !permanentID.isTemporaryID,
   905→              let refreshed = viewContext.object(with: permanentID) as? SouvenirEntity else {
   906→            print("❌ Could not obtain permanent souvenir after save")
   907→            return
   908→        }
   909→        onReadyToShare?(refreshed)
   910→    }
